/// Result of attempting to accept a thought into the substrate.
#[derive(Debug, Clone)]
pub enum AcceptResult {
    /// Thought accepted: commutator vanished, coherence decreased, group preserved.
    Accepted {
        coherence_reduction: Q,
        compound_depth: usize,
    },
    /// Commutator non-zero — thoughts conflict in specific relational directions.
    NonCongruent {
        conflict_magnitude: Q,
    },
    /// Commutator vanished but coherence did not decrease — thought is redundant.
    NoImprovement {
        delta_coherence: Q,
    },
    /// Compound lost invertibility — group membership violated.
    GroupViolation,
}

