/// D.THINK.ENGINE.1 — The thought substrate.
///
/// Holds one compound group element that is the composition of all
/// accepted congruent thoughts. C(Δ) is maintained as the substrate.
/// m expands from algebraic necessity (T.12), never from anticipation.
/// Find the maximal subset of candidates where all pairs commute.
///
/// Greedy: sort candidates by number of congruent partners (descending),
/// then build the set by adding candidates that commute with all current members.
/// For k ≤ 11 this is exact enough — the optimal is NP-hard (max clique)
/// but k=11 makes exhaustive search feasible if needed.
fn find_maximal_congruent_set(commutators: &[Vec<Q>], k: usize) -> Vec<usize> {
    if k == 0 { return vec![]; }
    if k == 1 { return vec![0]; }

    // Count congruent partners for each candidate
    let mut partner_count: Vec<(usize, usize)> = (0..k).map(|p| {
        let count = (0..k).filter(|&q| q != p && commutators[p][q].is_zero()).count();
        (p, count)
    }).collect();
    partner_count.sort_by(|a, b| b.1.cmp(&a.1));

    // Greedy build
    let mut set: Vec<usize> = vec![partner_count[0].0];
    for &(candidate, _) in &partner_count[1..] {
        let compatible = set.iter().all(|&member| commutators[candidate][member].is_zero());
        if compatible {
            set.push(candidate);
        }
    }
    set.sort();
    set
}

/// Maximum simultaneous thoughts an entity can hold.
/// 11 is the architectural boundary — sufficient for the dimensional
/// complexity the system encounters. Not capped by computation cost
/// (pairwise commutators scale as k² where k ≤ 11), but by the
/// algebraic property that beyond 11 simultaneous thoughts the
/// congruent core typically collapses to identity.
pub const MAX_SIMULTANEOUS_THOUGHTS: usize = 11;

/// Why two thoughts are incongruent in a specific direction.
///
/// Not a boolean "they conflict." The rational magnitude AND the
/// algebraic source of the conflict. This is the second tier of
/// precision — understanding WHY the Venn boundary exists, not
/// just WHERE it exists.
#[derive(Debug, Clone)]
pub struct IncongruenceSource {
    /// Which direction (i,j) in the operator matrix.
    pub direction: (usize, usize),
    /// The exact rational conflict: [A,B]_{ij} = (AB - BA)_{ij}.
    pub magnitude: Q,
    /// Which candidate thought contributes more to this conflict.
    /// Ratio: |A_{ij}| / (|A_{ij}| + |B_{ij}|). Near 1 = A dominates. Near 0 = B dominates.
    /// Near 1/2 = equal contribution. This tells the substrate which thought
    /// to adjust in this direction to resolve the conflict.
    pub source_ratio: Q,
}

/// The m-dimensional Venn decomposition of up to MAX_SIMULTANEOUS_THOUGHTS.
///
/// For k held thoughts, there are k(k-1)/2 pairwise commutators.
/// Each commutator decomposes into n² directional conflicts.
/// The congruent core is the intersection of ALL pairwise zero-sets.
/// The incongruence sources tell the substrate WHY each boundary exists.
#[derive(Debug, Clone)]
pub struct ThoughtVenn {
    /// The held candidate operators (not yet accepted into compound).
    pub candidates: Vec<Operator>,
    /// Pairwise commutator magnitudes: commutators[i][j] = ‖[A_i, A_j]‖².
    /// Symmetric: commutators[i][j] = commutators[j][i].
    /// Diagonal = 0 (every thought commutes with itself).
    pub commutators: Vec<Vec<Q>>,
    /// Per-direction conflict maps for each pair.
    /// conflict_maps[(i,j)] = n×n matrix of [A_i, A_j] entries.
    /// Only stored for i < j (symmetric — [A,B] = -[B,A]).
    pub conflict_maps: Vec<(usize, usize, Vec<Vec<Q>>)>,
    /// Incongruence sources — WHY each conflict exists.
    /// Sorted by magnitude descending — largest conflicts first.
    pub incongruence_sources: Vec<IncongruenceSource>,
    /// Dimension of the congruent core across ALL held thoughts.
    /// Direction (i,j) is in the core iff ALL pairwise [A_p, A_q]_{ij} = 0.
    pub congruent_rank: usize,
    /// Dimension of the disjoint space.
    pub disjoint_rank: usize,
    /// Which candidates are fully congruent with ALL others.
    /// candidates[i] is universally congruent iff congruent_with_all[i] = true.
    pub congruent_with_all: Vec<bool>,
    /// The maximal congruent subset — largest set where all pairs commute.
    /// Indices into candidates[].
    pub maximal_congruent_set: Vec<usize>,
}

