impl ThoughtSubstrate {
    /// Create a new substrate from an encoded Delta.
    /// The compound starts as identity. Coherence is C(Δ) of the raw state.
    pub fn new(delta: &Delta) -> Self {
        let n = delta.dim;
        let m = delta.m;
        let coherence = coherence_functional(delta);
        let id_matrix = matrix::identity(n);
        let compound = Operator {
            id: 0,
            matrix: id_matrix.clone(),
            matrix_inv: id_matrix,
            det_sign_positive: true,
        };
        let mut trajectory = Trajectory::new();
        trajectory.observe(coherence.clone());
        ThoughtSubstrate {
            compound, coherence, m, n, lineage: Vec::new(), held: None, trajectory,
            t_delta: None, coherence_t: Q::zero(),
        }
    }

    /// D.THINK.T.1 — Create a substrate from a transformation Delta.
    ///
    /// The substrate operates on T (the transformation), not the data.
    /// C(T) is tracked as the primary coherence measure. Thoughts that
    /// reduce C(T) decompose the transformation into simpler components.
    /// The compound of accepted thoughts IS the transmutation operator.
    pub fn from_transformation(t: &Delta) -> Self {
        let n = t.dim;
        let m = t.m;
        let c_t = coherence_functional(t);
        let id_matrix = matrix::identity(n);
        let compound = Operator {
            id: 0,
            matrix: id_matrix.clone(),
            matrix_inv: id_matrix,
            det_sign_positive: true,
        };
        let mut trajectory = Trajectory::new();
        trajectory.observe(c_t.clone());
        ThoughtSubstrate {
            compound,
            coherence: c_t.clone(),
            m, n,
            lineage: Vec::new(),
            held: None,
            trajectory,
            t_delta: Some(t.clone()),
            coherence_t: c_t,
        }
    }

    /// Accept a thought (group element) into the compound.
    ///
    /// Three conditions must hold:
    /// 1. [T_candidate, T_compound] = 0 — commutator vanishes (congruency)
    /// 2. C(Δ, T_new_compound) < C(Δ, T_compound) — coherence decreases
    /// 3. det(T_new_compound) ≠ 0 — group membership preserved
    ///
    /// The Delta is needed to compute coherence after conjugation.
    pub fn accept_thought(&mut self, candidate: &Operator, delta: &Delta) -> AcceptResult {
        // CONDITION 1: Commutator check
        // [A, B] = AB - BA. In matrix form over Q.
        let ab = matrix::mul(&candidate.matrix, &self.compound.matrix);
        let ba = matrix::mul(&self.compound.matrix, &candidate.matrix);
        let mut commutator_mag = Q::zero();
        for i in 0..self.n {
            for j in 0..self.n {
                let diff = &ab[i][j] - &ba[i][j];
                if !diff.is_zero() {
                    if diff < Q::zero() { commutator_mag -= &diff; } else { commutator_mag += &diff; }
                }
            }
        }
        if !commutator_mag.is_zero() {
            return AcceptResult::NonCongruent {
                conflict_magnitude: commutator_mag,
            };
        }

        // Compose: new_compound = candidate ∘ compound
        let new_matrix = matrix::mul(&candidate.matrix, &self.compound.matrix);
        let new_inv = match matrix::invert(&new_matrix) {
            Some(inv) => inv,
            None => return AcceptResult::GroupViolation,
        };

        // CONDITION 3: det > 0
        let new_det = matrix::det(&new_matrix);
        if new_det <= Q::zero() {
            return AcceptResult::GroupViolation;
        }

        let new_compound = Operator {
            id: self.lineage.len() + 1,
            matrix: new_matrix,
            matrix_inv: new_inv,
            det_sign_positive: true,
        };

        // CONDITION 2: Coherence must decrease
        // Apply new compound to delta: Δ' = T·Δ·T⁻¹
        let new_delta = match new_compound.apply(delta) {
            Ok(d) => d,
            Err(_) => return AcceptResult::GroupViolation,
        };
        let new_coherence = coherence_functional(&new_delta);

        if new_coherence >= self.coherence {
            return AcceptResult::NoImprovement {
                delta_coherence: &new_coherence - &self.coherence,
            };
        }

        // All three conditions met — accept
        let reduction = &self.coherence - &new_coherence;
        self.lineage.push(ThoughtReceipt {
            operator: candidate.clone(),
            coherence_before: self.coherence.clone(),
            coherence_after: new_coherence.clone(),
            commutator_magnitude: Q::zero(),
            k_at_acceptance: 0, // set by caller via set_last_k()
            anchor: ThoughtAnchor::Unanchored,
        });
        self.compound = new_compound;
        self.coherence = new_coherence.clone();
        self.trajectory.observe(new_coherence);

        AcceptResult::Accepted {
            coherence_reduction: reduction,
            compound_depth: self.lineage.len(),
        }
    }

    /// Has understanding been achieved? C(Δ) = 0 exactly.
    pub fn understood(&self) -> bool {
        self.coherence.is_zero()
    }

    /// Hold up to MAX_SIMULTANEOUS_THOUGHTS candidates and compute the
    /// full m-dimensional Venn decomposition.
    ///
    /// For k candidates: k(k-1)/2 pairwise commutators, each decomposed
    /// into n² directional conflicts. The congruent core is the intersection
    /// of ALL pairwise zero-sets. The incongruence sources tell the substrate
    /// WHY each boundary exists — which thought contributes what to each conflict.
    ///
    /// The thoughts are NOT accepted. They are held while the substrate
    /// evaluates their mutual structure.
    pub fn hold_thoughts(&mut self, candidates: &[Operator]) -> &ThoughtVenn {
        let k = candidates.len().min(MAX_SIMULTANEOUS_THOUGHTS);
        let n = self.n;
        let cands: Vec<Operator> = candidates[..k].to_vec();

        // Pairwise commutator magnitudes
        let mut commutators = vec![vec![Q::zero(); k]; k];
        let mut conflict_maps: Vec<(usize, usize, Vec<Vec<Q>>)> = Vec::new();
        let mut all_sources: Vec<IncongruenceSource> = Vec::new();

        // Track which directions are congruent across ALL pairs
        let mut direction_congruent = vec![vec![true; n]; n];

        for p in 0..k {
            for q in (p + 1)..k {
                let ab = matrix::mul(&cands[p].matrix, &cands[q].matrix);
                let ba = matrix::mul(&cands[q].matrix, &cands[p].matrix);

                let mut conflict = vec![vec![Q::zero(); n]; n];
                let mut pair_mag = Q::zero();

                for i in 0..n {
                    for j in 0..n {
                        let diff = &ab[i][j] - &ba[i][j];
                        if !diff.is_zero() {
                            if diff < Q::zero() { pair_mag -= &diff; } else { pair_mag += &diff; }
                            direction_congruent[i][j] = false;

                            // Source analysis: which candidate dominates this conflict?
                            let a_mag = {
                                let v = &cands[p].matrix[i][j];
                                if v < &Q::zero() { -v.clone() } else { v.clone() }
                            };
                            let b_mag = {
                                let v = &cands[q].matrix[i][j];
                                if v < &Q::zero() { -v.clone() } else { v.clone() }
                            };
                            let total = &a_mag + &b_mag;
                            let ratio = if total.is_zero() {
                                Q::new(BigInt::from(1), BigInt::from(2))
                            } else {
                                &a_mag / &total
                            };

                            all_sources.push(IncongruenceSource {
                                direction: (i, j),
                                magnitude: diff.clone(),
                                source_ratio: ratio,
                            });
                        }
                        conflict[i][j] = diff;
                    }
                }

                commutators[p][q] = pair_mag.clone();
                commutators[q][p] = pair_mag;
                conflict_maps.push((p, q, conflict));
            }
        }

        // Sort incongruence sources by magnitude descending
        all_sources.sort_by(|a, b| {
            let ma = if a.magnitude < Q::zero() { -a.magnitude.clone() } else { a.magnitude.clone() };
            let mb = if b.magnitude < Q::zero() { -b.magnitude.clone() } else { b.magnitude.clone() };
            mb.cmp(&ma)
        });

        // Count congruent vs disjoint
        let mut congruent_rank = 0;
        let mut disjoint_rank = 0;
        for i in 0..n {
            for j in 0..n {
                if direction_congruent[i][j] { congruent_rank += 1; } else { disjoint_rank += 1; }
            }
        }

        // Which candidates are congruent with all others?
        let congruent_with_all: Vec<bool> = (0..k).map(|p| {
            (0..k).all(|q| p == q || commutators[p][q].is_zero())
        }).collect();

        // Find maximal congruent subset (greedy: start from candidates with
        // most pairwise congruences, add compatible ones)
        let maximal_congruent_set = find_maximal_congruent_set(&commutators, k);

        self.held = Some(ThoughtVenn {
            candidates: cands,
            commutators,
            conflict_maps,
            incongruence_sources: all_sources,
            congruent_rank,
            disjoint_rank,
            congruent_with_all,
            maximal_congruent_set,
        });

        self.held.as_ref().unwrap()
    }

    /// Accept the maximal congruent subset of held thoughts into the compound.
    ///
    /// The maximal congruent set is the largest group where all pairs commute.
    /// These compose in any order (commutativity guarantees order-independence).
    /// Each is accepted sequentially — the algebra guarantees the result is
    /// the same regardless of acceptance order.
    ///
    /// Returns: the final AcceptResult, the number of accepted thoughts,
    /// and the number of disjoint directions remaining.
    pub fn accept_congruent_core(&mut self, delta: &Delta) -> Option<(AcceptResult, usize, usize)> {
        let venn = self.held.take()?;
        if venn.candidates.is_empty() { return None; }

        let congruent_set = &venn.maximal_congruent_set;
        if congruent_set.is_empty() {
            // No pair commutes — accept the single candidate that reduces C most
            let mut best_idx = 0;
            let mut best_c = self.coherence.clone();
            for (idx, cand) in venn.candidates.iter().enumerate() {
                let test_compound = matrix::mul(&cand.matrix, &self.compound.matrix);
                if let Some(inv) = matrix::invert(&test_compound) {
                    let op = Operator { id: 0, matrix: test_compound, matrix_inv: inv, det_sign_positive: true };
                    if let Ok(d) = op.apply(delta) {
                        let c = coherence_functional(&d);
                        if c < best_c { best_c = c; best_idx = idx; }
                    }
                }
            }
            let result = self.accept_thought(&venn.candidates[best_idx], delta);
            return Some((result, 1, venn.disjoint_rank));
        }

        // Accept all thoughts in the congruent set.
        // Persistence: evaluate every candidate. A plateau at operator N
        // does not mean operator N+1 won't resolve the residual.
        let mut last_result = AcceptResult::NoImprovement { delta_coherence: Q::zero() };
        let mut accepted = 0;
        for &idx in congruent_set {
            let result = self.accept_thought(&venn.candidates[idx], delta);
            match &result {
                AcceptResult::Accepted { .. } => { accepted += 1; last_result = result; }
                _ => { last_result = result; }
            }
        }

        let remaining_disjoint = if accepted == venn.candidates.len() { 0 } else { venn.disjoint_rank };
        Some((last_result, accepted, remaining_disjoint))
    }

    /// Set the K-index and anchor on the most recently accepted thought.
    pub fn set_last_anchor(&mut self, k_index: u64, anchor: ThoughtAnchor) {
        if let Some(last) = self.lineage.last_mut() {
            last.k_at_acceptance = k_index;
            last.anchor = anchor;
        }
    }

    /// T.TRANSMUTE.2 — Transmute the substrate to a new dimension.
    ///
    /// Lifts the compound operator and all lineage operators from GL_n to GL_{new_n}
    /// via block-diagonal embedding. Recomputes coherence at the new dimension.
    /// Preserves congruence relations: [lift(A), lift(B)] = lift([A, B]).
    ///
    /// The old grammar survives inside the new — all prior congruences are preserved.
    /// The new dimension starts as identity (orthogonal to existing structure).
    pub fn transmute_n(&mut self, new_delta: &Delta) -> bool {
        let new_n = new_delta.dim;
        if new_n <= self.n { return false; }

        // Lift compound operator
        let lifted_compound = match matrix::lift_operator(&self.compound, new_n) {
            Some(op) => op,
            None => return false,
        };

        // Lift all lineage operators
        let mut lifted_lineage = Vec::with_capacity(self.lineage.len());
        for receipt in &self.lineage {
            match matrix::lift_operator(&receipt.operator, new_n) {
                Some(lifted_op) => {
                    lifted_lineage.push(ThoughtReceipt {
                        operator: lifted_op,
                        coherence_before: receipt.coherence_before.clone(),
                        coherence_after: receipt.coherence_after.clone(),
                        commutator_magnitude: receipt.commutator_magnitude.clone(),
                        k_at_acceptance: receipt.k_at_acceptance,
                        anchor: receipt.anchor.clone(),
                    });
                }
                None => return false,
            }
        }

        // Recompute coherence at new dimension
        let new_coherence = match lifted_compound.apply(new_delta) {
            Ok(d) => coherence_functional(&d),
            Err(_) => return false,
        };

        // Commit transmutation
        self.compound = lifted_compound;
        self.lineage = lifted_lineage;
        self.coherence = new_coherence;
        self.n = new_n;
        self.m = new_delta.m;
        true
    }

    /// D.ARC.GROUP.PRODUCT.1 — Navigate via G_SPATIAL (conjugation).
    ///
    /// Uses perception::search_operator (coordinator normal equations)
    /// to find the next congruent spatial thought from the residual.
    pub fn navigate_spatial(&mut self, source: &Delta, target: &Delta) -> Option<AcceptResult> {
        let current = self.compound.apply(source).ok()?;
        let (candidate, _d_before, _d_after) = perception::search_operator(&current, target)?;
        Some(self.accept_thought(&candidate, source))
    }

    /// D.ARC.GROUP.PRODUCT.1 — Navigate via G_VALUE (value action).
    ///
    /// When conjugation (G_SPATIAL) produces rank-deficient AᵀA,
    /// the transformation is a value-level change — reachable only
    /// by G_VALUE. The value operator directly computes the per-cell
    /// value changes needed and builds the corresponding Delta modifier.
    ///
    /// Returns (value_changes, dist_before, dist_after).
    pub fn navigate_value(
        &self, source: &Delta, target: &Delta,
        source_values: &[i64], target_values: &[i64],
    ) -> Option<(Vec<Q>, Q, Q)> {
        let current = self.compound.apply(source).ok()?;
        perception::search_value_operator(&current, target, source_values, target_values)
    }

    /// Navigate with iterated refinement using BOTH group actions.
    ///
    /// Strategy: try G_SPATIAL (conjugation) first. If AᵀA is singular
    /// (returns None), try G_VALUE (value action). The algebra determines
    /// which action is needed — the residual reveals it.
    pub fn navigate_iterated(
        &mut self, source: &Delta, target: &Delta, max_iters: usize,
    ) -> Option<AcceptResult> {
        let mut last_result = None;
        for _ in 0..max_iters {
            if self.understood() { break; }
            let current = self.compound.apply(source).ok()?;
            // Try G_SPATIAL first
            match perception::search_operator(&current, target) {
                Some((candidate, d_before, _)) => {
                    if d_before.is_zero() { break; }
                    let result = self.accept_thought(&candidate, source);
                    match &result {
                        AcceptResult::Accepted { .. } => { last_result = Some(result); }
                        _ => { last_result = Some(result); }
                    }
                }
                None => {
                    // G_SPATIAL rank-deficient — conjugation cannot reach the residual.
                    // This IS the algebraic proof that G_VALUE is needed.
                    // For now, report the finding. The value action navigator
                    // is called separately with cell values.
                    break;
                }
            }
        }
        last_result
    }
}

