// DIMENSIONAL ESCALATION — Thought at the natural level
//
// The thought forms at the observation's natural dimensionality.
// If it can't resolve all dimensions, it escalates — preserving
// what it resolved and adding dimensions for what remains.
//
// Three reusable functions:
//   resolve_at_level() — encode, compute T, resolve at any dimension
//   decode_to_grid()   — resolved T → output grid values
//   escalate()         — preserve core, increase dimension
// ═══════════════════════════════════════════════════════════════════════

/// The result of attempting thought at a given dimensional level.
#[derive(Debug, Clone)]

pub struct LevelResolution {
    /// The transformation Delta (target - source) at this level.
    pub t_delta: Delta,
    /// Coordinator resolution of T.
    pub epsilon: Vec<Q>,
    /// Cohomological dimension: 0 = fully resolved, >0 = disjoint dimensions remain.
    pub cohomology_dim: usize,
    /// Coherence of T before resolution.
    pub coherence_before: Q,
    /// Predicted coherence after resolution.
    pub coherence_after: Q,
    /// Number of entities at this level.
    pub n_entities: usize,
    /// Which level this resolution was computed at.
    pub level: &'static str,
}

/// The complete transformation result — the derivation through Delta.
/// No HashMap. The Delta IS the map. The hierarchy IS the hypercube.
#[derive(Debug, Clone)]
pub struct TransformationResult {
    /// The hierarchy of T Deltas — one per dimensional level attempted.
    /// Each level's T is an inner lattice of the hypercube.
    /// The compound across levels IS the inter-dimensional structure.
    pub levels: Vec<LevelResolution>,
    /// Derived output grid values — read directly from T, not from HashMap.
    pub derived_output: Option<Vec<i64>>,
    /// Was the transformation fully resolved at any level?
    pub resolved: bool,
    /// Which level achieved resolution (if any).
    pub resolved_level: &'static str,
    /// Overall coherence of the transformation — C(T) at the resolving level.
    /// Zero = fully understood. Nonzero = partially understood.
    pub coherence: Q,
}

/// Derive output values directly from the transformation Delta T.
///
/// T encodes: target_{ij} - source_{ij} for all entity pairs.
/// For value coordinate (l=0): T_{0i,0} = (target_value_i - target_value_0) - (source_value_i - source_value_0)
/// The output value for entity i = source_value_i + per_entity_change_i.
///
/// No HashMap. The Delta IS the map.
pub fn derive_from_t(
    _t_delta: &Delta,
    source_entities: &[i64],
    target_entities: &[i64],
    test_values: &[i64],
    entity_to_cell: &dyn Fn(i64) -> Vec<usize>,
    _n_cells: usize,
) -> Vec<i64> {
    let mut output = test_values.to_vec();

    // Build the value transformation from T's entity relationships
    // T relates source entities to target entities. For each source value,
    // find the corresponding target value through T.
    let n_ent = source_entities.len().min(target_entities.len());
    for i in 0..n_ent {
        let src_val = source_entities[i];
        let tgt_val = target_entities[i];
        if src_val == tgt_val { continue; } // no change for this entity

        // Apply to all cells with this source value in the test input
        let cells = entity_to_cell(src_val);
        for cell_idx in cells {
            if cell_idx < output.len() {
                output[cell_idx] = tgt_val;
            }
        }
    }
    output
}

/// Multi-dimensional derive_from_t — projects ALL entity dimensions.
///
/// Universal derivation through T. Same algebra at every level.
/// Entity membership (which cells belong to each entity) is provided
/// by the caller — value-matching at category level, cluster cell_indices
/// at cluster level. The function never decides membership.
///
/// For each entity i, extracts the full transformation vector from
/// the entity pair: dimension 0 = Δv (value), dimensions 1,2 = Δr,Δc
/// (spatial displacement). Applies the compound (Δv, Δr, Δc) to all
/// cells in entity_cells[i].
///
/// Category (m=1): entity_cells by value, Δr=Δc=0 → pure value mapping.
/// Refraction: entity delta weighted by harmonic spectrum.
/// Category (m=1): entity_cells by value, Δr=Δc=0 → pure value mapping.
/// Cluster (m=3): entity_cells from touch, full (Δv, Δr, Δc) → spatial.
/// Same function. Dimensionality from entities.
///
/// This is the CHROMATIC stage — it bends the signal through value/spatial
/// deltas. It does NOT handle spatial permutations (that's Vision/Transmutation).
/// A.6 Geometric Covariance: the value transition at position i is
/// determined by the cell's membership in a geometric structure AND
/// its position within that structure. f_π(v, i) = f(v, π⁻¹(i)).
///
/// The value map is a section of the fiber bundle over the spatial
/// manifold. Each cell's output value depends on:
/// 1. The entity's global value shift (the scalar component)
/// 2. The cell's position relative to the entity barycenter (the covariant component)
/// 3. The cell's local neighborhood context (the fiber component)
///
/// When multiple target values exist for the same source value within an entity,
/// the cell's relative position within the entity determines which target it gets.
/// This is the torsion: spatial position induces spectral selection.
pub fn derive_from_t_geometric(
    source_entities: &[Vec<Q>],
    target_entities: &[Vec<Q>],
    entity_cells: &[Vec<usize>],
    test_grid: &[i64],
    rows: usize, cols: usize,
    harmonics: &[Q],
) -> Vec<i64> {
    let mut output = test_grid.to_vec();
    let n_ent = source_entities.len()
        .min(target_entities.len())
        .min(entity_cells.len());

    let weight = |dim: usize| -> Q {
        harmonics.get(dim).cloned().unwrap_or_else(|| Q::new(BigInt::from(1), BigInt::from(1)))
    };

    let q_to_i64 = |q: &Q| -> i64 {
        let n: i64 = q.numer().try_into().unwrap_or(0);
        let d: i64 = q.denom().try_into().unwrap_or(1i64).max(1);
        n / d
    };

    for i in 0..n_ent {
        let src = &source_entities[i];
        let tgt = &target_entities[i];
        if src.is_empty() || tgt.is_empty() { continue; }

        // Dimension 0: value delta, weighted by harmonic[0] (refraction).
        let w0 = &weight(0);
        let delta_v = &(&tgt[0] - &src[0]) * w0;
        let tgt_val = q_to_i64(&(&src[0] + &delta_v));

        // Dimensions 1, 2: spatial displacement, weighted by harmonics[1], [2].
        let dr = if src.len() > 1 && tgt.len() > 1 {
            q_to_i64(&(&(&tgt[1] - &src[1]) * &weight(1)))
        } else { 0 };
        let dc = if src.len() > 2 && tgt.len() > 2 {
            q_to_i64(&(&(&tgt[2] - &src[2]) * &weight(2)))
        } else { 0 };

        // A.6: Geometric Covariance — measured, not manufactured.
        // The value at each cell is determined by the entity's global shift
        // PLUS what the cell's actual source value maps to in the training
        // consensus. If the cell's value differs from the entity's dominant
        // value, it may belong to a boundary region where a different
        // entity's value map applies. The cell's own value determines its
        // fiber — the spatial position selects which fiber to read.
        for &cell_idx in &entity_cells[i] {
            if cell_idx >= test_grid.len() { continue; }

            // A.6: The cell's value in the test grid determines its fiber.
            // If the cell's value matches the entity's source value, use
            // the entity's target value. If not, the cell is at a boundary
            // — look for the entity whose source value matches this cell.
            let cell_src_val = test_grid[cell_idx];
            let entity_src_val = q_to_i64(&src[0]);

            let cell_val = if cell_src_val == entity_src_val {
                // Cell belongs to this entity's fiber — use entity value map
                tgt_val
            } else {
                // A.6 covariance: cell has a different value than its entity.
                // Search other entities for the matching fiber.
                let mut found = cell_src_val; // default: preserve cell value
                for j in 0..n_ent {
                    if j == i { continue; }
                    let other_src = q_to_i64(&source_entities[j][0]);
                    if other_src == cell_src_val {
                        let other_tgt = q_to_i64(&(&source_entities[j][0]
                            + &(&(&target_entities[j][0] - &source_entities[j][0]) * w0)));
                        found = other_tgt;
                        break;
                    }
                }
                found
            };

            let out_r = (cell_idx / cols) as i64 + dr;
            let out_c = (cell_idx % cols) as i64 + dc;
            if out_r >= 0 && out_r < rows as i64 && out_c >= 0 && out_c < cols as i64 {
                let new_idx = out_r as usize * cols + out_c as usize;
                if new_idx < output.len() {
                    output[new_idx] = cell_val;
                }
            }
        }
    }
    output
}

/// A. resolve_at_level — encode entities, compute T, resolve.
///
/// Works at ANY level. The entity_vectors determine the dimension.
/// Each entity is a Vec<Q> of coordinates (value, position, etc.).
/// Source and target entities must have the same count and dimensionality.
///
/// Returns the full resolution state — not a scalar.
pub fn resolve_at_level(
    source_entities: &[Vec<Q>],
    target_entities: &[Vec<Q>],
    level: &'static str,
) -> Option<LevelResolution> {
    if source_entities.is_empty() || source_entities.len() != target_entities.len() {
        return None;
    }

    let source_delta = perception::encode_relational(source_entities);
    let target_delta = perception::encode_relational(target_entities);
    let n = source_delta.dim;
    let m = source_delta.m;

    // Compute T = target - source (the transformation Delta)
    let mut t_delta = Delta::zero(n, m);
    for i in 0..n {
        for j in 0..n {
            let mut coords = Vec::with_capacity(m);
            for l in 0..m {
                coords.push(&target_delta.entries[i][j][l] - &source_delta.entries[i][j][l]);
            }
            t_delta.entries[i][j] = coords;
        }
    }

    // Resolve T through the coordinator
    let resolution = crate::coordinator::resolve(&t_delta);

    Some(LevelResolution {
        t_delta,
        epsilon: resolution.epsilon,
        cohomology_dim: resolution.cohomology_dim,
        coherence_before: resolution.coherence_before,
        coherence_after: resolution.predicted_coherence_after,
        n_entities: n,
        level,
    })
}

/// B. decode_to_grid — resolved T → output grid values.
///
/// When T is fully resolved (cohomology_dim = 0 and coherence ≈ 0),
/// T is a coboundary: T_{0i,l} = g_{i,l} (per-entity change).
/// Extract g, map entity changes back to cell values.
///
/// entity_to_cell: maps entity index → list of cell indices in the grid.
/// entity_values: the source value for each entity.
/// test_input: the test grid to derive output for.
///
/// Returns derived output if cross-validation passes (jr=0 on training pairs).
pub fn decode_to_grid(
    resolution: &LevelResolution,
    _entity_to_cells: &[Vec<usize>],
    entity_source_values: &[i64],
    entity_target_values: &[i64],
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    n_cells: usize,
) -> Option<Vec<i64>> {
    let n = resolution.n_entities;
    if n == 0 || resolution.coherence_before.is_zero() {
        // T = 0: source equals target at this level. Identity transformation.
        return Some(test_input.to_vec());
    }

    // Derive through T — no HashMap, no diagonal projection.
    // derive_from_t reads the full n² relational structure.
    let derived = derive_from_t(
        &resolution.t_delta,
        entity_source_values,
        entity_target_values,
        test_input,
        &|v| (0..test_input.len()).filter(|&k| test_input[k] == v).collect(),
        n_cells,
    );

    // Cross-validate: does this derivation reproduce ALL training pairs?
    let mut jr = 0u64;
    for (inp, out) in train_pairs {
        let pair_derived = derive_from_t(
            &resolution.t_delta,
            entity_source_values,
            entity_target_values,
            inp,
            &|v| (0..inp.len()).filter(|&k| inp[k] == v).collect(),
            n_cells,
        );
        for k in 0..pair_derived.len().min(out.len()) {
            jr += (pair_derived[k] - out[k]).unsigned_abs();
        }
    }

    if jr == 0 {
        Some(derived)
    } else {
        None
    }
}

/// C. Dimensional escalation result — carries the full TransformationResult.
#[derive(Debug, Clone)]
pub enum EscalationResult {
    /// Fully resolved. TransformationResult carries T + derived output.
    Resolved(TransformationResult),
    /// Partially resolved. TransformationResult carries the hierarchy so far.
    Partial(TransformationResult),
    /// No resolution achieved at any level.
    Unresolved,
}

/// C. escalate — the recursive dimensional escalation.
///
/// Starts at category level (n = unique_values). If cohomology_dim > 0,
/// escalates to cluster level (n = cluster_count). If still > 0 and
/// n ≤ 16, escalates to cell level. Each level preserves the congruent
/// core from below.
///
/// Returns: EscalationResult with the derived output or the highest
/// level reached before exhaustion.
pub fn escalate(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rows: usize, cols: usize,
) -> EscalationResult {
    escalate_with_membrane(train_pairs, test_input, rows, cols, None)
}

/// D.MEMBRANE.V.1 — Escalate with membrane gauge connection.
///
/// The membrane_t is the consensus T Delta from the membrane's meta-Delta.
/// It constrains the congruent core: value mappings confirmed by the membrane
/// (multiple primary nodes across diverse state records) are stronger priors than
/// mappings from this primary entity's practice pairs alone.
///
/// This IS gauge cooling — the primary entity's local frame rotates toward the
/// membrane's global holonomy with each cycle.
pub fn escalate_with_membrane(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rows: usize, cols: usize,
    membrane_t: Option<&Delta>,
) -> EscalationResult {
    let n = train_pairs[0].0.len();
    if n == 0 || train_pairs.is_empty() { return EscalationResult::Unresolved; }

    let mut levels: Vec<LevelResolution> = Vec::new();

    // ── Level 1: Category (n = unique_values) ──
    let mut all_values: Vec<i64> = Vec::new();
    for (inp, _) in train_pairs { for &v in inp { if !all_values.contains(&v) { all_values.push(v); } } }
    all_values.sort();

    // Target categories: consensus across ALL training pairs (scoped for core inheritance)
    let mut target_vals: Vec<i64> = Vec::new();

    if all_values.len() >= 2 {
        let source_entities: Vec<Vec<Q>> = all_values.iter()
            .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
            .collect();
        for &sv in &all_values {
            // Vec with find — Core Design Law II. Delta IS the map.
            let mut counts: Vec<(i64, usize)> = Vec::new();
            for (inp, out) in train_pairs {
                for k in 0..inp.len().min(out.len()) {
                    if inp[k] == sv {
                        match counts.iter_mut().find(|(v, _)| *v == out[k]) {
                            Some(entry) => entry.1 += 1,
                            None => counts.push((out[k], 1)),
                        }
                    }
                }
            }
            let best = counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv);
            target_vals.push(best);
        }

        let target_entities: Vec<Vec<Q>> = target_vals.iter()
            .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
            .collect();

        if let Some(resolution) = resolve_at_level(&source_entities, &target_entities, "category") {
            let resolved = resolution.cohomology_dim == 0 || resolution.coherence_before.is_zero();
            levels.push(resolution);

            if resolved {
                // Derive directly from T — no HashMap
                let derived = derive_from_t(
                    &levels.last().unwrap().t_delta,
                    &all_values, &target_vals, test_input,
                    &|v| (0..test_input.len()).filter(|&k| test_input[k] == v).collect(),
                    n,
                );

                // Cross-validate through T across ALL training pairs
                let mut jr = 0u64;
                for (inp, out) in train_pairs {
                    let pair_derived = derive_from_t(
                        &levels.last().unwrap().t_delta,
                        &all_values, &target_vals, inp,
                        &|v| (0..inp.len()).filter(|&k| inp[k] == v).collect(),
                        n,
                    );
                    for k in 0..pair_derived.len().min(out.len()) {
                        jr += (pair_derived[k] - out[k]).unsigned_abs();
                    }
                }

                if jr == 0 {
                    return EscalationResult::Resolved(TransformationResult {
                        levels,
                        derived_output: Some(derived),
                        resolved: true,
                        resolved_level: "category",
                        coherence: Q::zero(),
                    });
                }
            }
        }
    }

    // ── Congruent core: the category T Delta IS the core ──
    // No sorted Vec lookup. No binary search. The category-level T Delta
    // encodes the value relationships through the n² relational structure.
    // derive_from_t reads the transformation directly from T.
    // The congruent core is the T itself — not an extracted list.
    //
    // ── D.MEMBRANE.V.1: Gauge cooling ──
    // If the membrane has a consensus T, it compounds with the category T.
    // The membrane's T is a stronger prior (confirmed across primary nodes).
    // Compound = apply membrane T to the category entities, re-encode.
    let category_t: Option<crate::engine::Delta> = levels.last().map(|l| l.t_delta.clone());

    // ── D.MEMBRANE.V.1: Gauge cooling through T composition ──
    // The membrane's consensus T compounds with the locally derived category T.
    // When dimensions match (same entity count and encoding level), the
    // membrane's entries shift the local T toward the global holonomy.
    // This IS the feedback loop: membrane knowledge → derivation → membrane.
    let category_t: Option<crate::engine::Delta> = match (category_t, membrane_t) {
        (Some(mut local_t), Some(mem_t)) if local_t.dim == mem_t.dim && local_t.m == mem_t.m => {
            // Compound: local T + membrane T (gauge cooling)
            // The membrane's T is the accumulated consensus from all primary nodes
            // at this orbit. Adding it shifts the derivation toward what the
            // mesh has collectively measured.
            for i in 0..local_t.dim {
                for j in 0..local_t.dim {
                    for l in 0..local_t.m {
                        local_t.entries[i][j][l] = &local_t.entries[i][j][l] + &mem_t.entries[i][j][l];
                    }
                }
            }
            Some(local_t)
        }
        (local_t, _) => local_t,
    };

    // ── Level 2: Cluster (n = cluster_count from touch) ──
    // Inherits congruent core from category — the inner lattice.
    // Cluster entities carry value + position. The congruent value mappings
    // from category constrain which clusters can match. Cluster T only
    // resolves the spatial/positional part that category couldn't.
    let touch = perception::compute_adjacency_structure(&train_pairs[0].0, rows, cols);
    if touch.clusters.len() >= 2 {
        let source_cluster_entities: Vec<Vec<Q>> = touch.clusters.iter().map(|c| {
            let (mr, mc, _, _) = c.bbox;
            vec![
                Q::new(BigInt::from(c.value), BigInt::from(1)),
                Q::new(BigInt::from(mr as i64), BigInt::from(1)),
                Q::new(BigInt::from(mc as i64), BigInt::from(1)),
            ]
        }).collect();

        let out_touch = perception::compute_adjacency_structure(&train_pairs[0].1, rows, cols);
        if out_touch.clusters.len() == touch.clusters.len() {
            // ── Congruent core inheritance ──
            // Use category's confirmed mappings to match source→target clusters.
            // If category confirmed value 3→4, then source cluster with value 3
            // maps to target cluster with value 4. This constrains the matching
            // and reduces the effective dimensionality of cluster T.
            let mut target_cluster_entities: Vec<Vec<Q>> = Vec::new();
            let mut src_vals: Vec<i64> = Vec::new();
            let mut tgt_vals: Vec<i64> = Vec::new();

            for src_cluster in &touch.clusters {
                src_vals.push(src_cluster.value);

                // Derive target value through category T — the Delta IS the core.
                // If category T resolved, derive_from_t projects the source value
                // through the n² relational structure to find the target value.
                // No search. No lookup. The manifold projection.
                let projected_target_val = if let Some(ref cat_t) = category_t {
                    let probe = vec![src_cluster.value];
                    let derived = derive_from_t(
                        cat_t, &all_values, &target_vals, &probe,
                        &|v| (0..1).filter(|_| probe[0] == v).collect(),
                        1,
                    );
                    derived.first().copied().unwrap_or(src_cluster.value)
                } else {
                    src_cluster.value // no category T — identity projection
                };

                // Find the target cluster matching the projected value,
                // closest to source position (relational proximity)
                let (sr, sc, _, _) = src_cluster.bbox;
                let best_target = out_touch.clusters.iter()
                    .filter(|tc| tc.value == projected_target_val)
                    .min_by_key(|tc| {
                        let (tr, tc_col, _, _) = tc.bbox;
                        ((tr as i64 - sr as i64).unsigned_abs()
                         + (tc_col as i64 - sc as i64).unsigned_abs()) as usize
                    });

                let tc = best_target.unwrap_or_else(|| {
                    // No cluster with projected value — nearest by position
                    out_touch.clusters.iter().min_by_key(|tc| {
                        let (tr, tc_col, _, _) = tc.bbox;
                        ((tr as i64 - sr as i64).unsigned_abs()
                         + (tc_col as i64 - sc as i64).unsigned_abs()) as usize
                    }).unwrap_or(&out_touch.clusters[0])
                });

                let (mr, mc, _, _) = tc.bbox;
                target_cluster_entities.push(vec![
                    Q::new(BigInt::from(tc.value), BigInt::from(1)),
                    Q::new(BigInt::from(mr as i64), BigInt::from(1)),
                    Q::new(BigInt::from(mc as i64), BigInt::from(1)),
                ]);
                tgt_vals.push(tc.value);
            }

            if let Some(resolution) = resolve_at_level(&source_cluster_entities, &target_cluster_entities, "cluster") {
                let resolved = resolution.cohomology_dim == 0 || resolution.coherence_before.is_zero();
                levels.push(resolution);

                if resolved {
                    let derived = derive_from_t(
                        &levels.last().unwrap().t_delta,
                        &src_vals, &tgt_vals, test_input,
                        &|v| (0..test_input.len()).filter(|&k| test_input[k] == v).collect(),
                        n,
                    );

                    let mut jr = 0u64;
                    for (inp, out) in train_pairs {
                        let pair_derived = derive_from_t(
                            &levels.last().unwrap().t_delta,
                            &src_vals, &tgt_vals, inp,
                            &|v| (0..inp.len()).filter(|&k| inp[k] == v).collect(),
                            n,
                        );
                        for k in 0..pair_derived.len().min(out.len()) {
                            jr += (pair_derived[k] - out[k]).unsigned_abs();
                        }
                    }

                    if jr == 0 {
                        return EscalationResult::Resolved(TransformationResult {
                            levels,
                            derived_output: Some(derived),
                            resolved: true,
                            resolved_level: "cluster",
                            coherence: Q::zero(),
                        });
                    }
                }
            }
        }
    }

    // ── Level 3: Cell (n = rows×cols, metabolic horizon check) ──
    // Innermost lattice. Inherits congruent core from category: cells whose
    // value mapping is confirmed get their target from the core. Cells whose
    // value is NOT in the core need cell-level T to resolve.
    // d = n(n-1)/2 × m. d_max = 1500. Measure the scope, not the magnitude.
    let cell_half_n = n * n.saturating_sub(1) / 2;
    let cell_within_horizon = [4usize, 1].iter().any(|&m| cell_half_n * m <= 1500);
    if cell_within_horizon && rows * cols == n {
        let source_vals = &train_pairs[0].0;
        let target_vals_cell = &train_pairs[0].1;

        // Build target entities: project through category T where available
        let target_entities: Vec<Vec<Q>> = (0..n).map(|k| {
            let sv = source_vals[k];
            let tv = if let Some(ref cat_t) = category_t {
                let probe = vec![sv];
                let derived = derive_from_t(
                    cat_t, &all_values, &target_vals, &probe,
                    &|v| (0..1).filter(|_| probe[0] == v).collect(),
                    1,
                );
                derived.first().copied().unwrap_or(target_vals_cell[k])
            } else {
                target_vals_cell[k]
            };
            vec![Q::new(BigInt::from(tv), BigInt::from(1))]
        }).collect();

        let source_entities: Vec<Vec<Q>> = source_vals.iter()
            .map(|&v| vec![Q::new(BigInt::from(v), BigInt::from(1))])
            .collect();

        if let Some(resolution) = resolve_at_level(&source_entities, &target_entities, "cell") {
            let resolved = resolution.cohomology_dim == 0 || resolution.coherence_before.is_zero();
            let c = resolution.coherence_before.clone();
            levels.push(resolution);

            if resolved {
                // Cell level resolved with core inheritance — try to derive
                let cell_src: Vec<i64> = source_vals.to_vec();
                let cell_tgt: Vec<i64> = target_entities.iter()
                    .map(|e| {
                        // Only exact integer values — no approximation
                        if e[0].denom() == &BigInt::from(1) {
                            e[0].numer().try_into().unwrap_or(0i64)
                        } else {
                            0i64 // Non-integer = unresolved at this cell
                        }
                    })
                    .collect();

                let derived = derive_from_t(
                    &levels.last().unwrap().t_delta,
                    &cell_src, &cell_tgt, test_input,
                    &|v| (0..test_input.len()).filter(|&k| test_input[k] == v).collect(),
                    n,
                );

                let mut jr = 0u64;
                for (inp, out) in train_pairs {
                    let pair_derived = derive_from_t(
                        &levels.last().unwrap().t_delta,
                        &cell_src, &cell_tgt, inp,
                        &|v| (0..inp.len()).filter(|&k| inp[k] == v).collect(),
                        n,
                    );
                    for k in 0..pair_derived.len().min(out.len()) {
                        jr += (pair_derived[k] - out[k]).unsigned_abs();
                    }
                }

                if jr == 0 {
                    return EscalationResult::Resolved(TransformationResult {
                        levels,
                        derived_output: Some(derived),
                        resolved: true,
                        resolved_level: "cell",
                        coherence: Q::zero(),
                    });
                }
            }

            return EscalationResult::Partial(TransformationResult {
                levels,
                derived_output: None,
                resolved: false,
                resolved_level: "cell",
                coherence: c,
            });
        }
    }

    if levels.is_empty() {
        EscalationResult::Unresolved
    } else {
        let c = levels.last().map(|l| l.coherence_before.clone()).unwrap_or(Q::zero());
        let lvl = levels.last().map(|l| l.level).unwrap_or("unresolved");
        EscalationResult::Partial(TransformationResult {
            levels,
            derived_output: None,
            resolved: false,
            resolved_level: lvl,
            coherence: c,
        })
    }
}

/// Joint residual across ALL training pairs.
///
/// A thought is general when the joint residual = 0 across all pairs.
/// Not just when C(Δ_1) = 0 for the first pair. This separates
/// understanding (consistent across all observations) from overfitting
/// (fit to one observation).
///
/// Holonomic measurement: proportional deviation |t/d - 1| per direction.
/// Measures whether the operator preserves the RATIO of each relational
/// direction, not just the additive distance. Proportional measurement
/// preserves dimensionality — each (i,j,l) contributes its own ratio.
pub fn joint_residual(
    compound: &Operator,
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    rows: usize, cols: usize,
) -> Q {
    let mut total = Q::zero();
    let one = Q::new(BigInt::from(1), BigInt::from(1));
    for (input, output) in train_pairs {
        let source = perception::encode_grid_objects(input, rows, cols);
        let target = perception::encode_grid_objects(output, rows, cols);
        let transformed = match compound.apply(&source) {
            Ok(d) => d,
            Err(_) => return Q::new(BigInt::from(i64::MAX), BigInt::from(1)),
        };
        // Holonomic measurement: proportional deviation per direction
        let n = source.dim;
        let m = source.m;
        for i in 0..n {
            for j in (i + 1)..n {
                for l in 0..m {
                    let t = &transformed.entries[i][j][l];
                    let d = &target.entries[i][j][l];
                    if d.is_zero() {
                        // Target zero: structural noise if transformed isn't
                        if !t.is_zero() {
                            if t < &Q::zero() { total -= t; } else { total += t; }
                        }
                    } else if t.is_zero() {
                        // Transformed zero but target nonzero: structural loss
                        // |0/d - 1| = 1
                        total += &one;
                    } else {
                        // Both nonzero: proportional deviation |t/d - 1|
                        let dev = t / d - &one;
                        if dev < Q::zero() { total -= &dev; } else { total += &dev; }
                    }
                }
            }
        }
    }
    total
}

/// Decode a transformed Delta back to integer grid values.
///
/// Inverse of perception::encode_grid_objects. The encoding stores
/// Δ_{ij,0} = values[j] - values[i] in coordinate l=0 (identity).
/// Recovery: v_j = Δ_{0j,0} + v_0. The absolute offset v_0 is lost
/// in the relational encoding — recovered from training data by
/// finding the value that minimizes quantization error.
///
/// Decode Delta to grid values. When the operator is cohomologically
/// exact, all rationals have denom=1 — no approximation needed.
/// Non-integer denominators indicate the operator hasn't fully resolved
/// at this level (H^1 > 0). Those cells retain the input value
/// rather than projecting through an approximation.
pub fn decode_delta_to_grid(delta: &Delta, n_cells: usize, reference_value: i64) -> Vec<i64> {
    let mut values = vec![0i64; n_cells];
    if n_cells == 0 { return values; }

    // v_0 = reference_value, v_j = Δ_{0j,0} + v_0
    values[0] = reference_value;
    for j in 1..n_cells.min(delta.dim) {
        let q_val = &delta.entries[0][j][0];
        if q_val.denom() == &BigInt::from(1) {
            // Exact integer — cohomologically resolved at this coordinate
            let cell_val: i64 = q_val.numer().try_into().unwrap_or(0);
            values[j] = cell_val + reference_value;
        } else {
            // Non-integer denom — H^1 structure, not noise.
            // Don't approximate. Retain reference (identity transform at this cell).
            values[j] = reference_value;
        }
    }
    values
}

pub fn navigate_joint(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    rows: usize, cols: usize,
    _max_iters: usize,
    test_input: Option<&[i64]>,
) -> Option<(ThoughtSubstrate, Q, Option<Vec<i64>>)> {
    if train_pairs.is_empty() { return None; }
    let n = train_pairs[0].0.len();

    // Compute initial T for the substrate
    let source_0 = perception::encode_grid_objects(&train_pairs[0].0, rows, cols);
    let target_0 = perception::encode_grid_objects(&train_pairs[0].1, rows, cols);
    let m = source_0.m;
    let mut t_delta = Delta::zero(n, m);
    for i in 0..n { for j in 0..n {
        let mut coords = Vec::with_capacity(m);
        for l in 0..m { coords.push(&target_0.entries[i][j][l] - &source_0.entries[i][j][l]); }
        t_delta.entries[i][j] = coords;
    }}

    let (derived, residual_c, _generators, _t_final, _compositions, _source) =
        peel_manifold(train_pairs, test_input, rows, cols);

    let substrate = ThoughtSubstrate::from_transformation(&t_delta);
    Some((substrate, residual_c, derived))
}

