/// Read current RSS in kB from /proc/self/status. O(1) syscall.
/// Used at peel-loop phase boundaries for survival governance.
fn read_rss_kb() -> u64 {
    let mut rss = 0u64;
    if let Ok(status) = std::fs::read_to_string("/proc/self/status") {
        for line in status.lines() {
            if line.starts_with("VmRSS:") {
                rss = line.split_whitespace()
                    .nth(1)
                    .and_then(|s| s.parse().ok())
                    .unwrap_or(0);
                break;
            }
        }
    }
    rss
}

/// Navigate joint: compute T, peel the manifold, report the result.
///
/// Delegates to peel_manifold for derivation. The substrate carries T.
/// The residual C is the holonomic measurement — not a boolean gate.
/// The result of manifold derivation — what remains after peeling.
/// VIII.4: ValueMap(HashMap) and PerCell removed. No dimensional collapse.
/// Derivation flows through T. SpatialRelation is relational (Vec, not HashMap).
#[derive(Debug, Clone)]
pub enum FactoredRule {
    /// Spatial-relational: anchor_color + offset → fill_value.
    /// Each entry: (anchor_color, fill_color, [(dr, dc), ...]).
    /// Relational structure preserved — Vec, not HashMap.
    SpatialRelation(Vec<(i64, i64, Vec<(i32, i32)>)>),
    /// No rule found — honest non-resolution.
    NoRule,
}

impl FactoredRule {
    /// Apply the factored rule to a new input grid.
    /// Returns predicted output values.
    pub fn apply(&self, input: &[i64], rows: usize, cols: usize) -> Vec<i64> {
        match self {
            FactoredRule::SpatialRelation(pairs) => {
                let mut result = input.to_vec();
                let n = input.len().min(rows * cols);
                if n == 0 { return result; }
                for &(anchor, fill, ref offsets) in pairs {
                    for k in 0..n {
                        if input[k] != anchor { continue; }
                        let r = k / cols;
                        let c = k % cols;
                        for &(dr, dc) in offsets {
                            let nr = r as i32 + dr;
                            let nc = c as i32 + dc;
                            if nr >= 0 && nr < rows as i32 && nc >= 0 && nc < cols as i32 {
                                let nidx = nr as usize * cols + nc as usize;
                                if result[nidx] == 0 { result[nidx] = fill; }
                            }
                        }
                    }
                }
                result
            }
            FactoredRule::NoRule => input.to_vec(),
        }
    }

    /// BLAKE3 hash of the discovered rule (canonical byte representation).
    pub fn canonical_hash(&self) -> [u8; 32] {
        let mut hasher = blake3::Hasher::new();
        hasher.update(b"SAIOS-THOUGHT-RULE-v1");
        match self {
            FactoredRule::SpatialRelation(rels) => {
                hasher.update(b"SpatialRelation");
                for &(anchor, fill, ref offsets) in rels {
                    hasher.update(&anchor.to_be_bytes());
                    hasher.update(&fill.to_be_bytes());
                    for &(dr, dc) in offsets {
                        hasher.update(&dr.to_be_bytes());
                        hasher.update(&dc.to_be_bytes());
                    }
                }
            }
            FactoredRule::NoRule => {
                hasher.update(b"NoRule");
            }
        }
        *hasher.finalize().as_bytes()
    }

    /// Verify the rule across ALL training pairs. Returns joint residual.
    pub fn joint_residual_values(&self, pairs: &[(Vec<i64>, Vec<i64>)], rows: usize, cols: usize) -> u64 {
        let mut total: u64 = 0;
        for (inp, out) in pairs {
            let predicted = self.apply(inp, rows, cols);
            for k in 0..predicted.len().min(out.len()) {
                total += (predicted[k] - out[k]).unsigned_abs();
            }
        }
        total
    }
}

