// ═══════════════════════════════════════════════════════════════════════

/// Complete thinking pipeline for an ARC puzzle.
///
/// 1. Compute transformation signature
/// 2. Check knowledge base (recognition)
/// 3. If not recognized: think (iterate vocabulary)
/// 4. If understood: store in knowledge base
/// 5. Apply thought to test input → prediction
pub fn think_and_solve(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rows: usize, cols: usize,
    knowledge: &mut KnowledgeBase,
) -> Option<(Vec<i64>, ThinkingResult)> {
    think_and_solve_with_state(train_pairs, test_input, rows, cols, knowledge, &[])
}

/// Think with genomic vocabulary expansion.
/// Composed operators from the state record enter the compositor at depth 1.
pub fn think_and_solve_with_state(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rows: usize, cols: usize,
    knowledge: &mut KnowledgeBase,
    composed_operators: &[crate::engine::ComposedOperator],
) -> Option<(Vec<i64>, ThinkingResult)> {
    if train_pairs.is_empty() { return None; }

    let sig = perception::transformation_signature(train_pairs);

    // Recognition: do we already know this?
    if let Some((thought, _comprehension)) = knowledge.recognize(&sig) {
        let predicted = thought.apply_to_values(test_input, rows, cols);
        return Some((predicted, ThinkingResult {
            best_thought: thought.clone(),
            distance: 0,
            understood: true,
            thoughts_evaluated: 0, // recognized, not thought
            depth: 0,
        }));
    }

    // Think: iterate vocabulary with genomic words at depth 1
    let result = thought_vocabulary_with_state(train_pairs, rows, cols, composed_operators);

    // If understood: remember (with empty comprehension — caller can upgrade)
    if result.understood {
        knowledge.remember(sig, result.best_thought.clone(), rows, cols, ComprehensionRecord::empty());
    }

    // Apply best thought to test input
    let predicted = result.best_thought.apply_to_values(test_input, rows, cols);

    Some((predicted, result))
}

