// T.10 — Commutator Gate at the Thought Level
// D.THINK.CONGRUENCE.1 — Thought Congruency via Exact Commutator
// ═══════════════════════════════════════════════════════════════════════

/// Compute the commutator [T_a, T_b](input) = T_a(T_b(input)) - T_b(T_a(input)).
/// Returns the L1 norm of the commutator vector.
/// Zero means the thoughts commute — they are congruent.
pub fn thought_commutator(
    t_a: &Thought, t_b: &Thought,
    input: &[i64], rows: usize, cols: usize,
) -> u64 {
    // T_a(T_b(input))
    let b_first = t_b.apply_to_values(input, rows, cols);
    let ab = t_a.apply_to_values(&b_first, rows, cols);
    // T_b(T_a(input))
    let a_first = t_a.apply_to_values(input, rows, cols);
    let ba = t_b.apply_to_values(&a_first, rows, cols);
    // [T_a, T_b] = ab - ba
    ab.iter().zip(ba.iter()).map(|(a, b)| (a - b).unsigned_abs()).sum()
}

/// D.THINK.CONGRUENCE.1 — Test whether two thoughts are congruent
/// across ALL training pairs.
///
/// Congruent iff:
///   (a) [T_a, T_b](input) = 0 for all training inputs (commutator vanishes)
///   (b) C(Δ, T_a ∘ T_b) < C(Δ, T_a) AND < C(Δ, T_b) (composition improves both)
///
/// Returns (congruent, commutator_magnitude) where magnitude is the total
/// commutator norm across all training pairs.
pub fn thoughts_congruent(
    t_a: &Thought, t_b: &Thought,
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    rows: usize, cols: usize,
) -> (bool, u64) {
    let mut total_commutator: u64 = 0;
    let mut dist_a: u64 = 0;
    let mut dist_b: u64 = 0;
    let mut dist_composed: u64 = 0;

    let composed = Thought::Compose(Box::new(t_a.clone()), Box::new(t_b.clone()));

    for (inp, out) in train_pairs {
        // Commutator check
        total_commutator += thought_commutator(t_a, t_b, inp, rows, cols);
        // Distance checks
        let (da, _) = thought_score(t_a, inp, out, rows, cols);
        let (db, _) = thought_score(t_b, inp, out, rows, cols);
        let (dc, _) = thought_score(&composed, inp, out, rows, cols);
        dist_a += da;
        dist_b += db;
        dist_composed += dc;
    }

    // Congruent: commutator vanishes AND composition improves over both
    let congruent = total_commutator == 0
        && dist_composed < dist_a
        && dist_composed < dist_b;

    (congruent, total_commutator)
}

/// D.MESH.CONJOIN.1 — Conjoin partial understandings through group product
/// with D.THINK.CONGRUENCE.1 commutator gate.
///
/// Before composing two thoughts, the commutator gate checks congruency.
/// Congruent pairs compose immediately. Non-congruent pairs are rejected —
/// the commutator residual is information about WHERE they conflict.
///
/// The compound does NOT need to be in any vocabulary. It emerges from
/// the group structure. Any composition of congruent thoughts is valid.
pub fn conjoin_partial_understandings(
    partials: &[PartialUnderstanding],
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    rows: usize, cols: usize,
) -> Option<(Thought, u64)> {
    if partials.is_empty() { return None; }
    if partials.len() == 1 {
        return Some((partials[0].thought.clone(), partials[0].distance));
    }

    // Sort by distance (ascending) — best partial first
    let mut sorted: Vec<&PartialUnderstanding> = partials.iter().collect();
    sorted.sort_by_key(|p| p.distance);

    let mut best_compound: Option<(Thought, u64)> = None;

    // Pairwise compositions — commutator gate enforced
    for i in 0..sorted.len().min(8) {
        for j in 0..sorted.len().min(8) {
            if i == j { continue; }

            // T.10 COMMUTATOR GATE: check congruency before composing
            let (congruent, comm_mag) = thoughts_congruent(
                &sorted[i].thought, &sorted[j].thought,
                train_pairs, rows, cols,
            );

            if congruent {
                // Congruent — compose through group product
                let composed = Thought::Compose(
                    Box::new(sorted[i].thought.clone()),
                    Box::new(sorted[j].thought.clone()),
                );
                let total_dist: u64 = train_pairs.iter()
                    .map(|(inp, out)| thought_score(&composed, inp, out, rows, cols).0)
                    .sum();
                if total_dist == 0 {
                    return Some((composed, 0)); // Compound understanding achieved
                }
                match &best_compound {
                    None => best_compound = Some((composed, total_dist)),
                    Some((_, d)) if total_dist < *d => best_compound = Some((composed, total_dist)),
                    _ => {}
                }
            } else if comm_mag == 0 {
                // Commutator vanishes but composition doesn't improve both.
                // Still try — they don't conflict, just one dominates.
                let composed = Thought::Compose(
                    Box::new(sorted[i].thought.clone()),
                    Box::new(sorted[j].thought.clone()),
                );
                let total_dist: u64 = train_pairs.iter()
                    .map(|(inp, out)| thought_score(&composed, inp, out, rows, cols).0)
                    .sum();
                if total_dist == 0 {
                    return Some((composed, 0));
                }
                match &best_compound {
                    None => best_compound = Some((composed, total_dist)),
                    Some((_, d)) if total_dist < *d => best_compound = Some((composed, total_dist)),
                    _ => {}
                }
            }
            // else: non-zero commutator — thoughts conflict, do NOT compose.
            // The commutator magnitude is the measure of conflict.
        }
    }

    // If no congruent pair found, try compositions anyway (backwards compat)
    // but only if nothing was found above
    if best_compound.is_none() {
        for i in 0..sorted.len().min(5) {
            for j in 0..sorted.len().min(5) {
                if i == j { continue; }
                let composed = Thought::Compose(
                    Box::new(sorted[i].thought.clone()),
                    Box::new(sorted[j].thought.clone()),
                );
                let total_dist: u64 = train_pairs.iter()
                    .map(|(inp, out)| thought_score(&composed, inp, out, rows, cols).0)
                    .sum();
                if total_dist == 0 {
                    return Some((composed, 0));
                }
                match &best_compound {
                    None => best_compound = Some((composed, total_dist)),
                    Some((_, d)) if total_dist < *d => best_compound = Some((composed, total_dist)),
                    _ => {}
                }
            }
        }
    }

    best_compound
}

// ═══════════════════════════════════════════════════════════════════════
// EVOLVE — The agent identifies what it's missing and asks for translation
// ═══════════════════════════════════════════════════════════════════════

/// Algebraic properties derived from the residual field.
/// These are MEASURED, not enumerated. The entity discovers them.
#[derive(Debug, Clone)]
pub struct AlgebraicProperties {
    /// Periodicity: does the residual repeat with some period along rows/cols/diag?
    pub periodicity: Option<usize>,
    /// Axis of periodicity: 0=row, 1=col, 2=diagonal, None=no axis
    pub periodic_axis: Option<u8>,
    /// Rank of the residual change matrix (how many independent change directions)
    pub rank: usize,
    /// Symmetry: is the residual symmetric under any grid transformation?
    pub symmetric_h: bool,
    pub symmetric_v: bool,
    pub symmetric_diag: bool,
    /// Density: fraction of cells that have non-zero residual
    pub density: (u32, u32),
    /// Seed extractable: can non-zero cells be explained by a small repeating seed?
    pub seed_extractable: bool,
    /// Seed if extractable
    pub seed: Vec<i64>,
    /// Is the change a function of position only?
    pub position_dependent: bool,
    /// Is the change a function of value only (injective color mapping)?
    pub value_dependent: bool,
    /// Spatial pattern of non-zero residual cells.
    pub nonzero_pattern: SpatialPattern,
    /// Is the mapping bijective (injective + surjective)?
    pub is_bijective: bool,
    /// Minimum composition depth.
    pub min_composition_depth: usize,
    /// Nullspace dimension.
    pub nullspace_dim: usize,
    // ── Deepened m=3 consequences (theorems of position coordinates) ──
    /// Adjacency dependent: >80% of changed cells neighbor a dominant color.
    pub adjacency_dependent: bool,
    /// The dominant adjacent color if adjacency_dependent.
    pub anchor_color: Option<i64>,
    /// ALL anchor-fill pairs: each non-background color that triggers fills.
    /// Each entry: (anchor_color, fill_color, measured_offsets).
    /// The offsets are the exact (dr, dc) vectors from anchor to filled cells,
    /// MEASURED from the training data. No named patterns. The measurement.
    /// Multiple entries means MULTIPLE congruent thoughts are needed.
    pub anchor_fill_pairs: Vec<(i64, i64, Vec<(i32, i32)>)>,
    /// Distance dependent: output values = L1 distance from anchor cells.
    pub distance_dependent: bool,
    /// Number of connected components of changed cells (region structure).
    pub num_change_components: u32,
}

/// Compute matrix rank via Gaussian elimination over Q.
fn compute_matrix_rank(mat: &[Vec<Q>]) -> usize {
    if mat.is_empty() { return 0; }
    let rows = mat.len();
    let cols = mat[0].len();
    let mut work: Vec<Vec<Q>> = mat.to_vec();
    let mut rank = 0;

    for col in 0..cols {
        // Find pivot
        let mut pivot = None;
        for row in rank..rows {
            if !work[row][col].is_zero() { pivot = Some(row); break; }
        }
        let pivot = match pivot { Some(p) => p, None => continue };

        work.swap(rank, pivot);
        let pivot_val = work[rank][col].clone();

        // Eliminate below
        for row in (rank + 1)..rows {
            if work[row][col].is_zero() { continue; }
            let factor = &work[row][col] / &pivot_val;
            for j in col..cols {
                let sub = &factor * &work[rank][j];
                work[row][j] = &work[row][j] - &sub;
            }
        }
        rank += 1;
    }
    rank
}

/// Classify the spatial pattern of non-zero positions.
#[derive(Debug, Clone, PartialEq)]
pub enum SpatialPattern {
    Diagonal,
    AntiDiagonal,
    Border,
    Block,
    Scattered,
    Full,
}

fn classify_nonzero_pattern(nonzero_positions: &[(usize, usize)], rows: usize, cols: usize) -> SpatialPattern {
    if nonzero_positions.is_empty() { return SpatialPattern::Full; }
    let total = rows * cols;
    if nonzero_positions.len() == total { return SpatialPattern::Full; }

    // Check diagonal
    let is_diagonal = nonzero_positions.iter().all(|&(r, c)| r == c);
    if is_diagonal && rows == cols { return SpatialPattern::Diagonal; }

    // Check anti-diagonal
    let is_antidiag = nonzero_positions.iter().all(|&(r, c)| r + c == rows - 1);
    if is_antidiag && rows == cols { return SpatialPattern::AntiDiagonal; }

    // Check border
    let is_border = nonzero_positions.iter().all(|&(r, c)| {
        r == 0 || r == rows - 1 || c == 0 || c == cols - 1
    });
    if is_border { return SpatialPattern::Border; }

    // Check if positions form a rectangular block
    if nonzero_positions.len() >= 4 {
        let min_r = nonzero_positions.iter().map(|p| p.0).min().unwrap();
        let max_r = nonzero_positions.iter().map(|p| p.0).max().unwrap();
        let min_c = nonzero_positions.iter().map(|p| p.1).min().unwrap();
        let max_c = nonzero_positions.iter().map(|p| p.1).max().unwrap();
        let block_size = (max_r - min_r + 1) * (max_c - min_c + 1);
        if block_size == nonzero_positions.len() { return SpatialPattern::Block; }
    }

    SpatialPattern::Scattered
}

/// ENTITY INTELLIGENCE: derive algebraic properties from the residual field.
///
/// Operates at m=3 minimum (identity, row, col) as the axiom requires.
/// The m=1 scalar difference is coordinate 0. Spatial structure is
/// in coordinates 1 and 2. T.12 expansion happens when rank-deficiency
/// at current m signals insufficient dimensionality.
///
/// Every property is derived from the m-dimensional differential,
/// not from flat value arrays.
pub fn derive_algebraic_properties(
    input: &[i64], output: &[i64],
    rows: usize, cols: usize,
) -> AlgebraicProperties {
    let n = input.len();
    let changes: Vec<i64> = (0..n).map(|i| output[i] - input[i]).collect();
    let nonzero: Vec<usize> = (0..n).filter(|&i| changes[i] != 0).collect();

    // m=3 ENCODING: also analyze the spatial structure of changes
    // Coordinate 0: identity (value change)
    // Coordinate 1: row position of change
    // Coordinate 2: col position of change
    // The spatial coordinates tell us WHERE changes happen, not just WHAT changes

    // Density
    let density = (nonzero.len() as u32, n as u32);

    // Rank: actual matrix rank via Gaussian elimination over Q
    // Build the change matrix: rows = grid rows, cols = grid cols
    let rank = if rows > 0 && cols > 0 {
        // Construct rational matrix of changes shaped as rows×cols
        let mut mat: Vec<Vec<Q>> = Vec::with_capacity(rows);
        for r in 0..rows {
            let row: Vec<Q> = (0..cols)
                .map(|c| Q::new(BigInt::from(changes[r * cols + c]), BigInt::from(1)))
                .collect();
            mat.push(row);
        }
        // Gaussian elimination to find rank
        compute_matrix_rank(&mat)
    } else { 0 };

    // Value dependent: does each input value consistently map to the same output value?
    let mut val_map: Vec<(i64, i64)> = Vec::new();
    let mut value_dependent = true;
    for i in 0..n {
        match val_map.iter().find(|(from, _)| *from == input[i]) {
            Some((_, to)) => { if *to != output[i] { value_dependent = false; break; } }
            None => val_map.push((input[i], output[i])),
        }
    }

    // Position dependent: does each position have a fixed change regardless of input value?
    // (Check across multiple training pairs if available — here we check single pair)
    let position_dependent = !value_dependent && nonzero.len() > 0;

    // Periodicity: check rows, cols, diagonal for repeating patterns
    let mut periodicity = None;
    let mut periodic_axis = None;

    // Row periodicity: do change values repeat with period P across columns?
    if cols > 1 {
        for p in 1..=cols/2 {
            let row_periodic = (0..rows).all(|r| {
                let row_changes: Vec<i64> = (0..cols).map(|c| changes[r*cols+c]).collect();
                (0..cols).all(|c| row_changes[c] == row_changes[c % p])
            });
            if row_periodic {
                periodicity = Some(p);
                periodic_axis = Some(0); // row axis
                break;
            }
        }
    }

    // Col periodicity
    if periodicity.is_none() && rows > 1 {
        for p in 1..=rows/2 {
            let col_periodic = (0..cols).all(|c| {
                let col_changes: Vec<i64> = (0..rows).map(|r| changes[r*cols+c]).collect();
                (0..rows).all(|r| col_changes[r] == col_changes[r % p])
            });
            if col_periodic {
                periodicity = Some(p);
                periodic_axis = Some(1);
                break;
            }
        }
    }

    // Diagonal periodicity: does OUTPUT[r][c] depend only on (r+c) % p?
    // This uses the SPATIAL coordinate (r+c) — the trajectory in the m=3 encoding.
    // The diagonal position IS coordinate 1 + coordinate 2 of the object differential.
    if periodicity.is_none() {
        for p in 1..=(rows + cols) / 2 {
            if p == 0 { continue; }
            let mut diag_map: Vec<(usize, i64)> = Vec::new();
            let mut diag_ok = true;
            for r in 0..rows {
                for c in 0..cols {
                    let key = (r + c) % p;
                    let val = output[r * cols + c];
                    match diag_map.iter().find(|(k, _)| *k == key) {
                        Some((_, v)) => { if *v != val { diag_ok = false; break; } }
                        None => diag_map.push((key, val)),
                    }
                }
                if !diag_ok { break; }
            }
            if diag_ok && p > 0 && p < rows + cols - 1 {
                periodicity = Some(p);
                periodic_axis = Some(2); // diagonal = coordinates 1+2 in m=3
                break;
            }
        }
    }

    // Anti-diagonal periodicity: does OUTPUT[r][c] depend only on (r-c+cols) % p?
    // This is the anti-trajectory — coordinate 1 - coordinate 2 in m=3.
    // If this matches but diagonal doesn't, we need m=4 (T.12 expansion).
    if periodicity.is_none() {
        for p in 1..=(rows + cols) / 2 {
            if p == 0 { continue; }
            let mut adiag_map: Vec<(usize, i64)> = Vec::new();
            let mut adiag_ok = true;
            for r in 0..rows {
                for c in 0..cols {
                    let key = ((r as i64 - c as i64 + cols as i64 * 2) as usize) % p;
                    let val = output[r * cols + c];
                    match adiag_map.iter().find(|(k, _)| *k == key) {
                        Some((_, v)) => { if *v != val { adiag_ok = false; break; } }
                        None => adiag_map.push((key, val)),
                    }
                }
                if !adiag_ok { break; }
            }
            if adiag_ok && p > 0 && p < rows + cols - 1 {
                periodicity = Some(p);
                periodic_axis = Some(3); // anti-diagonal = m=4 territory
                break;
            }
        }
    }

    // Symmetry checks on the output grid
    let symmetric_h = (0..rows/2).all(|r| {
        (0..cols).all(|c| output[r*cols+c] == output[(rows-1-r)*cols+c])
    });
    let symmetric_v = (0..rows).all(|r| {
        (0..cols/2).all(|c| output[r*cols+c] == output[r*cols+(cols-1-c)])
    });
    let symmetric_diag = rows == cols && (0..rows).all(|r| {
        (0..cols).all(|c| output[r*cols+c] == output[c*cols+r])
    });

    // Seed extraction: derive from the periodic structure
    // The seed IS the values at each residue class of the periodic axis.
    // For diagonal (axis 2): residue class = (r+c) % p
    // For anti-diagonal (axis 3): residue class = (r-c+cols) % p
    // For row (axis 0): residue class = c % p
    // For col (axis 1): residue class = r % p
    let mut seed_extractable = false;
    let mut seed = Vec::new();
    if let Some(p) = periodicity {
        if p > 0 {
            seed = (0..p).map(|k| {
                for r in 0..rows {
                    for c in 0..cols {
                        let residue = match periodic_axis {
                            Some(0) => c % p,       // row
                            Some(1) => r % p,       // col
                            Some(2) => (r + c) % p, // diagonal (coord 1 + coord 2)
                            Some(3) => ((r as i64 - c as i64 + (cols * 2) as i64) as usize) % p, // anti-diag
                            _ => 0,
                        };
                        if residue == k { return output[r * cols + c]; }
                    }
                }
                0
            }).collect();
            seed_extractable = true;
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // DEEPENING: derive MORE consequences from the m=3 differential.
    // These are THEOREMS of the position coordinates, not new measurements.
    // ═══════════════════════════════════════════════════════════════

    // THEOREM 1: Adjacency structure of changed cells.
    // ‖position_diff‖_L1 = 1 is adjacency. This is a FACT of coordinates 1,2.
    // For each changed cell: which input colors are at L1 distance = 1?
    // This discovers "changed cells are adjacent to color X" algebraically.
    let mut adjacency_color_counts: Vec<(i64, u32)> = Vec::new();
    for &idx in &nonzero {
        let r = idx / cols;
        let c = idx % cols;
        for &(dr, dc) in &[(-1i32,0),(1,0),(0,-1i32),(0,1)] {
            let nr = r as i32 + dr;
            let nc = c as i32 + dc;
            if nr >= 0 && nr < rows as i32 && nc >= 0 && nc < cols as i32 {
                let nval = input[nr as usize * cols + nc as usize];
                if nval != 0 {
                    match adjacency_color_counts.iter_mut().find(|(v, _)| *v == nval) {
                        Some(entry) => entry.1 += 1,
                        None => adjacency_color_counts.push((nval, 1)),
                    }
                }
            }
        }
    }
    let total_adj: u32 = adjacency_color_counts.iter().map(|(_, c)| *c).sum();
    let dominant_adj_color = adjacency_color_counts.iter()
        .max_by_key(|(_, count)| *count)
        .map(|&(color, count)| (color, count));
    let adjacency_dependent = if let Some((_, count)) = dominant_adj_color {
        total_adj > 0 && count * 5 >= total_adj * 4 // >80% threshold
    } else { false };

    // THEOREM 2: Distance structure from anchor cells.
    // For each changed cell, compute L1 distance to nearest anchor.
    // If output value = distance, the transformation IS a distance field.
    // L1 distance = |r1-r2| + |c1-c2| — derived from position coordinates.
    let anchor_color = dominant_adj_color.map(|(c, _)| c);
    let distance_dependent = if let Some(ac) = anchor_color {
        let anchors: Vec<(usize, usize)> = (0..n)
            .filter(|&i| input[i] == ac)
            .map(|i| (i / cols, i % cols))
            .collect();
        if !anchors.is_empty() {
            nonzero.iter().all(|&idx| {
                let r = idx / cols;
                let c = idx % cols;
                let min_dist = anchors.iter()
                    .map(|&(ar, ac)| (r as i64 - ar as i64).abs() + (c as i64 - ac as i64).abs())
                    .min()
                    .unwrap_or(0);
                output[idx] == min_dist
            })
        } else { false }
    } else { false };

    // THEOREM 2.5: FULL anchor-fill mapping (multi-anchor).
    // For EACH non-background input color, MEASURE the displacement vectors
    // from anchor cells to changed cells. The offsets are the exact (dr, dc)
    // coordinates — derived from m=3 position. No named patterns.
    // Each (anchor, fill_color, offsets) is a SEPARATE thought.
    let mut anchor_fill_pairs: Vec<(i64, i64, Vec<(i32, i32)>)> = Vec::new();
    {
        let mut input_colors: Vec<i64> = Vec::new();
        for &v in input.iter() {
            (v != 0 && !input_colors.contains(&v)).then(|| input_colors.push(v));
        }

        for &anchor in &input_colors {
            let anchor_positions: Vec<(usize, usize)> = (0..n)
                .filter(|&i| input[i] == anchor)
                .map(|i| (i / cols, i % cols))
                .collect();

            // For each changed cell, measure displacement to nearest anchor of this color.
            // Group by fill value. The offsets accumulate across all anchor instances.
            let mut fill_offsets: Vec<(i64, Vec<((i32,i32), u32)>)> = Vec::new();

            for &idx in &nonzero {
                let r = idx / cols;
                let c = idx % cols;
                let fill_val = output[idx];
                // Find nearest anchor of this color
                for &(ar, ac) in &anchor_positions {
                    let dr = r as i32 - ar as i32;
                    let dc = c as i32 - ac as i32;
                    // Only consider small displacements (L_inf <= 2)
                    if dr.abs() <= 2 && dc.abs() <= 2 && (dr != 0 || dc != 0) {
                        let offsets = match fill_offsets.iter_mut().find(|(fv, _)| *fv == fill_val) {
                            Some((_, ofs)) => ofs,
                            None => { fill_offsets.push((fill_val, Vec::new())); &mut fill_offsets.last_mut().unwrap().1 }
                        };
                        match offsets.iter_mut().find(|(o, _)| *o == (dr, dc)) {
                            Some(entry) => entry.1 += 1,
                            None => offsets.push(((dr, dc), 1)),
                        }
                    }
                }
            }

            // For each fill color, find the offset set that is consistent
            // across anchor instances (appears for every anchor of this color)
            let anchor_count = anchor_positions.len() as u32;
            for (fill_val, offset_counts) in &fill_offsets {
                let threshold = (anchor_count + 1) / 2;
                let mut consistent_offsets: Vec<(i32, i32)> = offset_counts.iter()
                    .filter(|(_, count)| *count >= threshold)
                    .map(|(offset, _)| *offset)
                    .collect();
                consistent_offsets.sort();

                if consistent_offsets.len() >= 2 {
                    anchor_fill_pairs.push((anchor, *fill_val, consistent_offsets));
                }
            }
        }
        anchor_fill_pairs.sort_by(|a, b| b.2.len().cmp(&a.2.len()));
    }

    // THEOREM 3: Connectivity / region structure.
    // Two cells are CONNECTED if they can be linked by a chain of L1-adjacent
    // cells with the same value. This is transitive closure of adjacency —
    // the cocycle condition applied to the connectivity coordinate.
    // If changed cells form connected regions bounded by specific colors,
    // the transformation is region-dependent.
    // Count connected components of changed cells:
    let mut visited = vec![false; n];
    let mut num_components = 0u32;
    for &start in &nonzero {
        if visited[start] { continue; }
        num_components += 1;
        // BFS flood fill
        let mut queue = vec![start];
        visited[start] = true;
        while let Some(idx) = queue.pop() {
            let r = idx / cols;
            let c = idx % cols;
            for &(dr, dc) in &[(-1i32,0),(1,0),(0,-1i32),(0,1)] {
                let nr = r as i32 + dr;
                let nc = c as i32 + dc;
                if nr >= 0 && nr < rows as i32 && nc >= 0 && nc < cols as i32 {
                    let nidx = nr as usize * cols + nc as usize;
                    if !visited[nidx] && changes[nidx] != 0 {
                        visited[nidx] = true;
                        queue.push(nidx);
                    }
                }
            }
        }
    }

    // Spatial pattern of non-zero change positions
    let nonzero_positions: Vec<(usize, usize)> = nonzero.iter()
        .map(|&idx| (idx / cols, idx % cols))
        .collect();
    let nonzero_pattern = classify_nonzero_pattern(&nonzero_positions, rows, cols);

    // Bijectivity: is the color mapping bijective?
    let is_bijective = if value_dependent {
        let out_vals: Vec<i64> = {
            let mut v: Vec<i64> = val_map.iter().map(|(_, to)| *to).collect();
            v.sort(); v.dedup(); v
        };
        out_vals.len() == val_map.len() // surjective if output values are also unique
    } else { false };

    // Composition depth: rank gives lower bound on independent operations
    let min_composition_depth = if rank <= 1 { 1 } else { rank.min(3) };

    // Nullspace: total dims minus rank
    let total_dims = rows.min(cols);
    let nullspace_dim = total_dims.saturating_sub(rank);

    AlgebraicProperties {
        periodicity,
        periodic_axis,
        rank,
        symmetric_h,
        symmetric_v,
        symmetric_diag,
        density,
        seed_extractable,
        seed,
        position_dependent,
        value_dependent,
        nonzero_pattern,
        is_bijective,
        min_composition_depth,
        nullspace_dim,
        adjacency_dependent,
        anchor_color,
        anchor_fill_pairs,
        distance_dependent,
        num_change_components: num_components,
    }
}

/// ENTITY INTELLIGENCE: construct a thought from derived algebraic properties.
///
/// If the vocabulary covers the properties → construct without LLM.
/// If not → the properties become the structured question upward.
pub fn construct_from_properties(
    props: &AlgebraicProperties,
    rows: usize, cols: usize,
) -> Option<Thought> {
    // Value dependent → color map (already handled by evolve pipeline)
    if props.value_dependent {
        return None; // handled by color_map strategy in evolve_and_solve
    }

    // Periodic with extractable seed → absolute target from any axis
    if props.seed_extractable && props.periodicity.is_some() {
        let p = props.periodicity.unwrap();
        if !props.seed.is_empty() && p > 0 {
            let seed = props.seed.clone();
            let axis = props.periodic_axis;
            let targets: Vec<i64> = (0..rows*cols).map(|idx| {
                let r = idx / cols;
                let c = idx % cols;
                let residue = match axis {
                    Some(0) => c % p,
                    Some(1) => r % p,
                    Some(2) => (r + c) % p,
                    Some(3) => ((r as i64 - c as i64 + (cols * 2) as i64) as usize) % p,
                    _ => 0,
                };
                seed[residue % seed.len()]
            }).collect();
            return Some(Thought::AbsoluteTarget(targets));
        }
    }

    // Distance dependent: output = L1 distance from anchor
    if props.distance_dependent {
        if let Some(ac) = props.anchor_color {
            return Some(Thought::DistanceFromColor(ac));
        }
    }

    // Adjacency dependent with known anchor and single fill pair
    if props.adjacency_dependent && props.anchor_fill_pairs.len() == 1 {
        let (ac, fill, ref offsets) = props.anchor_fill_pairs[0];
        return Some(Thought::AdjacencyFill {
            anchor_color: ac,
            fill_color: fill,
            offsets: offsets.clone(),
        });
    }

    // Symmetric → reflection
    if props.symmetric_h && !props.symmetric_v {
        return Some(Thought::ReflectHorizontal);
    }
    if props.symmetric_v && !props.symmetric_h {
        return Some(Thought::ReflectVertical);
    }

    None
}

/// D.THINK.CONGRUENCE.1 — Construct MULTIPLE congruent thoughts from properties.
///
/// When derive_algebraic_properties finds multiple anchor-fill pairs, each pair
/// is a separate thought. The commutator gate verifies they are congruent
/// (act on disjoint regions). Their group product is the compound understanding.
///
/// Returns Vec<Thought> — each thought is a partial understanding.
/// The caller composes them through the congruent sluice.
pub fn construct_congruent_thoughts(
    props: &AlgebraicProperties,
    _input: &[i64],
    rows: usize, cols: usize,
) -> Vec<Thought> {
    let mut thoughts = Vec::new();

    // Multi-anchor: each (anchor, fill, offsets) is a separate thought
    // with its own measured displacement geometry
    if props.anchor_fill_pairs.len() >= 2 {
        for (anchor, fill, offsets) in &props.anchor_fill_pairs {
            thoughts.push(Thought::AdjacencyFill {
                anchor_color: *anchor,
                fill_color: *fill,
                offsets: offsets.clone(),
            });
        }
        return thoughts;
    }

    // Single thought from standard properties
    if let Some(t) = construct_from_properties(props, rows, cols) {
        thoughts.push(t);
    }

    thoughts
}

/// EVOLVE.1 — Residual structure: WHAT the agent doesn't understand.
/// Computed from the best failed thought's prediction vs expected output.
#[derive(Debug, Clone)]
pub struct ResidualStructure {
    /// Which cells differ between prediction and expected output.
    pub changed_cells: Vec<usize>,
    /// Are the changed cells contiguous in a row?
    pub row_contiguous: bool,
    /// Are the changed cells contiguous in a column?
    pub col_contiguous: bool,
    /// Is the change a permutation (same values, different positions)?
    pub is_permutation: bool,
    /// Is the change a uniform value shift?
    pub is_uniform_shift: bool,
    /// The shift amount if uniform.
    pub uniform_shift: i64,
    /// Is the change a fill (all changed cells become the same value)?
    pub is_fill: bool,
    /// The fill value if fill.
    pub fill_value: i64,
    /// Fraction of cells that changed.
    pub change_fraction: (u32, u32),
    /// Thoughts already tried and ruled out.
    pub ruled_out: Vec<String>,
}

/// EVOLVE.1 — Analyze what the agent doesn't understand.
pub fn analyze_residuals(
    predicted: &[i64],
    expected: &[i64],
    _rows: usize, cols: usize,
    ruled_out: Vec<String>,
) -> ResidualStructure {
    let n = predicted.len();
    let changed: Vec<usize> = (0..n).filter(|&i| predicted[i] != expected[i]).collect();

    // Contiguity check
    let row_contiguous = if changed.len() >= 2 {
        let first_row = changed[0] / cols;
        changed.iter().all(|&c| c / cols == first_row) &&
        changed.windows(2).all(|w| w[1] == w[0] + 1)
    } else { changed.len() <= 1 };

    let col_contiguous = if changed.len() >= 2 {
        let first_col = changed[0] % cols;
        changed.iter().all(|&c| c % cols == first_col) &&
        changed.windows(2).all(|w| w[1] == w[0] + cols)
    } else { changed.len() <= 1 };

    // Permutation check: same multiset of values?
    let mut pred_vals: Vec<i64> = changed.iter().map(|&i| predicted[i]).collect();
    let mut exp_vals: Vec<i64> = changed.iter().map(|&i| expected[i]).collect();
    pred_vals.sort();
    exp_vals.sort();
    let is_permutation = pred_vals == exp_vals;

    // Uniform shift?
    let shifts: Vec<i64> = changed.iter().map(|&i| expected[i] - predicted[i]).collect();
    let is_uniform_shift = !shifts.is_empty() && shifts.iter().all(|s| *s == shifts[0]);
    let uniform_shift = if is_uniform_shift && !shifts.is_empty() { shifts[0] } else { 0 };

    // Fill?
    let is_fill = !changed.is_empty() && changed.iter().all(|&i| expected[i] == expected[changed[0]]);
    let fill_value = if is_fill && !changed.is_empty() { expected[changed[0]] } else { 0 };

    // STAGE1.B: Additional structural pattern detection

    // Row-wise permutation: are values within each row just reordered?
    let _is_row_permutation = if n > 0 && cols > 0 {
        (0..n / cols).all(|row| {
            let start = row * cols;
            let end = (start + cols).min(n);
            let mut pred_row: Vec<i64> = (start..end).map(|i| predicted[i]).collect();
            let mut exp_row: Vec<i64> = (start..end).map(|i| expected[i]).collect();
            pred_row.sort();
            exp_row.sort();
            pred_row == exp_row
        })
    } else { false };

    // Block pattern: does the change repeat in a regular block pattern?
    let _block_size = if !changed.is_empty() && changed.len() >= 4 {
        // Check if changes repeat every B cells
        let diffs: Vec<i64> = changed.iter().map(|&i| expected[i] - predicted[i]).collect();
        let mut found_block = 0usize;
        for b in 2..=changed.len() / 2 {
            if diffs.len() % b == 0 {
                let pattern = &diffs[..b];
                if diffs.chunks(b).all(|chunk| chunk == pattern) {
                    found_block = b;
                    break;
                }
            }
        }
        found_block
    } else { 0 };

    ResidualStructure {
        change_fraction: (changed.len() as u32, n as u32),
        changed_cells: changed,
        row_contiguous,
        col_contiguous,
        is_permutation,
        is_uniform_shift,
        uniform_shift,
        is_fill,
        fill_value,
        ruled_out,
    }
}

/// EVOLVE.2 — Structured query to the higher echelon.
#[derive(Debug, Clone)]
pub struct SemanticQuery {
    /// What type of change is observed?
    pub change_type: String,
    /// Spatial pattern of the change.
    pub spatial_pattern: String,
    /// What has been ruled out.
    pub ruled_out: Vec<String>,
    /// Grid dimensions for context.
    pub rows: usize,
    pub cols: usize,
}

/// EVOLVE.2 — Formulate the question from residual analysis.
pub fn formulate_question(residuals: &ResidualStructure, rows: usize, cols: usize) -> SemanticQuery {
    let change_type = if residuals.is_permutation {
        "permutation".to_string()
    } else if residuals.is_uniform_shift {
        format!("uniform_shift_{}", residuals.uniform_shift)
    } else if residuals.is_fill {
        format!("fill_{}", residuals.fill_value)
    } else {
        "unknown".to_string()
    };

    let spatial_pattern = if residuals.row_contiguous {
        "row_contiguous".to_string()
    } else if residuals.col_contiguous {
        "col_contiguous".to_string()
    } else if residuals.change_fraction.0 == residuals.change_fraction.1 {
        "global".to_string()
    } else {
        format!("scattered_{}_of_{}", residuals.change_fraction.0, residuals.change_fraction.1)
    };

    SemanticQuery {
        change_type,
        spatial_pattern,
        ruled_out: residuals.ruled_out.clone(),
        rows, cols,
    }
}

/// EVOLVE.3+4 — Construct a new thought from a semantic response.
/// This is the C2R descending at the perception layer.
/// Maps semantic labels to exact grid operations.
pub fn construct_thought_from_semantic(label: &str, params: &Vec<(String, String)>) -> Option<Thought> {
    match label {
        "row_sort_ascending" => {
            Some(Thought::CellChange(vec![])) // placeholder — would need row-sort logic
        }
        "flood_fill" => {
            let fill_val: i64 = params.iter().find(|(k, _)| k == "value").and_then(|(_, v)| v.parse().ok()).unwrap_or(0);
            // Fill all cells with the fill value — simplistic but exact
            Some(Thought::UniformShift(fill_val))
        }
        "color_invert" => {
            let max_color: usize = params.iter().find(|(k, _)| k == "max_color").and_then(|(_, v)| v.parse().ok()).unwrap_or(9);
            let perm: Vec<usize> = (0..=max_color).map(|c| max_color - c).collect();
            Some(Thought::ColorPermute(perm))
        }
        "identity" => Some(Thought::Identity),
        "rotate_90" => Some(Thought::Rotate90),
        "rotate_180" => Some(Thought::Rotate180),
        "rotate_270" => Some(Thought::Rotate270),
        "reflect_vertical" => Some(Thought::ReflectVertical),
        "reflect_horizontal" => Some(Thought::ReflectHorizontal),
        _ => {
            // Try to parse "shift_N" pattern
            if label.starts_with("shift_") {
                if let Ok(k) = label[6..].parse::<i64>() {
                    return Some(Thought::UniformShift(k));
                }
            }
            // Try "swap_A_B" pattern
            if label.starts_with("swap_") {
                let parts: Vec<&str> = label.split('_').collect();
                if parts.len() == 3 {
                    if let (Ok(a), Ok(b)) = (parts[1].parse::<usize>(), parts[2].parse::<usize>()) {
                        let mut perm: Vec<usize> = (0..10).collect();
                        if a < 10 && b < 10 { perm[a] = b; perm[b] = a; }
                        return Some(Thought::ColorPermute(perm));
                    }
                }
            }
            None
        }
    }
}

/// EVOLVE.5 — Complete evolution loop.
///
/// Think → analyze residuals → formulate question → (simulate LLM response)
/// → construct thought → evaluate → if understood, store.
///
/// For now: the "LLM response" is simulated by analyzing the residual structure
/// and mapping it to known semantic labels. Full LLM integration is EVOLVE.3
/// wired through gRPC/API. The architecture is correct regardless of whether
/// the semantic translator is local heuristic or remote LLM.
pub fn evolve_and_solve(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rows: usize, cols: usize,
    knowledge: &mut KnowledgeBase,
) -> Option<(Vec<i64>, ThinkingResult)> {
    // Phase 1: Try existing vocabulary
    let result = think_and_solve(train_pairs, test_input, rows, cols, knowledge);
    if let Some((ref _pred, ref res)) = result {
        if res.understood { return result; }
    }

    // Phase 2: Analyze what's missing
    let base_result = thought_vocabulary_with_state(train_pairs, rows, cols, &[]);
    let best_pred = base_result.best_thought.apply_to_values(&train_pairs[0].0, rows, cols);
    let residuals = analyze_residuals(&best_pred, &train_pairs[0].1, rows, cols,
        vec![base_result.best_thought.name()]);
    let _query = formulate_question(&residuals, rows, cols);

    // Phase 2.5: ENTITY INTELLIGENCE at m=3 — derive algebraic properties
    // from the full object differential (identity + position + trajectory).
    // D.THINK.CONGRUENCE.1: if multiple anchor-fill pairs found, construct
    // multiple thoughts and compose through commutator-gated sluice.
    for (inp, out) in train_pairs {
        let props = derive_algebraic_properties(inp, out, rows, cols);

        // Try congruent multi-thought composition first
        let congruent_thoughts = construct_congruent_thoughts(&props, inp, rows, cols);
        if congruent_thoughts.len() >= 2 {
            // Multiple thoughts — check congruency and compose
            let mut congruent_partials: Vec<PartialUnderstanding> = Vec::new();
            for (idx, thought) in congruent_thoughts.iter().enumerate() {
                let total_dist: u64 = train_pairs.iter()
                    .map(|(i, o)| thought_score(thought, i, o, rows, cols).0)
                    .sum();
                congruent_partials.push(PartialUnderstanding {
                    thought: thought.clone(),
                    distance: total_dist,
                    entity_id: idx as u32,
                });
            }

            if let Some((compound, dist)) = conjoin_partial_understandings(
                &congruent_partials, train_pairs, rows, cols
            ) {
                if dist == 0 {
                    let sig = perception::transformation_signature(train_pairs);
                    knowledge.remember(sig, compound.clone(), rows, cols, ComprehensionRecord::empty());
                    let output_vals = compound.apply_to_values(test_input, rows, cols);
                    return Some((output_vals, ThinkingResult {
                        best_thought: compound,
                        distance: 0,
                        understood: true,
                        thoughts_evaluated: base_result.thoughts_evaluated + congruent_thoughts.len() as u32,
                        depth: 2,
                    }));
                }
            }
        }

        // Single thought path
        if let Some(thought) = construct_from_properties(&props, rows, cols) {
            let mut total_dist: u64 = 0;
            for (inp2, out2) in train_pairs {
                let prop_pred = thought.apply_to_values(inp2, rows, cols);
                let dist: u64 = prop_pred.iter().zip(out2.iter())
                    .map(|(p, o)| (p - o).unsigned_abs())
                    .sum();
                total_dist += dist;
            }
            if total_dist == 0 {
                let sig = perception::transformation_signature(train_pairs);
                knowledge.remember(sig, thought.clone(), rows, cols, ComprehensionRecord::empty());
                let output_vals = thought.apply_to_values(test_input, rows, cols);
                return Some((output_vals, ThinkingResult {
                    best_thought: thought,
                    distance: 0,
                    understood: true,
                    thoughts_evaluated: base_result.thoughts_evaluated + 1,
                    depth: 1,
                }));
            }
        }
    }

    // Phase 3: Construct thought DIRECTLY from residuals.
    let cells = train_pairs[0].0.len();

    let mut candidates: Vec<Thought> = Vec::new();

    // Strategy A: Direct cell change from the FIRST training pair
    // (CellChange with the exact per-cell differences)
    let exact_changes: Vec<i64> = (0..cells)
        .map(|c| train_pairs[0].1[c] - train_pairs[0].0[c])
        .collect();
    candidates.push(Thought::CellChange(exact_changes));

    // Strategy B: If residuals show uniform shift on the RESIDUAL
    // (the difference between best_pred and expected is uniform)
    if residuals.is_uniform_shift && residuals.uniform_shift != 0 {
        // The base thought was close — just add the uniform correction
        let correction = residuals.uniform_shift;
        let corrected: Vec<i64> = (0..cells)
            .map(|c| {
                let base_change = best_pred[c] - train_pairs[0].0[c];
                base_change + correction
            })
            .collect();
        candidates.push(Thought::CellChange(corrected));
    }

    // Strategy C: If it's a fill — all output cells have the same value
    if residuals.is_fill {
        let fill_val = residuals.fill_value;
        let fill_changes: Vec<i64> = (0..cells)
            .map(|c| fill_val - train_pairs[0].0[c])
            .collect();
        candidates.push(Thought::CellChange(fill_changes));
    }

    // Strategy D: Try to find a COLOR MAPPING that works globally
    // For each input color, what output color does it map to?
    // Core Design Law II: Vec with find, not HashMap. Delta IS the map.
    let mut color_map: Vec<(i64, i64)> = Vec::new();
    let mut consistent = true;
    for (inp, out) in train_pairs {
        for c in 0..cells {
            match color_map.iter().find(|(from, _)| *from == inp[c]) {
                Some((_, to)) => { if *to != out[c] { consistent = false; break; } }
                None => color_map.push((inp[c], out[c])),
            }
        }
        if !consistent { break; }
    }
    if consistent && !color_map.is_empty() {
        let max_color = color_map.iter().map(|(f, _)| *f).max().unwrap_or(9) as usize;
        let max_val = color_map.iter().map(|(_, t)| *t).max().unwrap_or(9) as usize;
        let perm_size = max_color.max(max_val) + 1;
        let mut perm: Vec<usize> = (0..perm_size).collect();
        for &(from, to) in &color_map {
            if (from as usize) < perm_size { perm[from as usize] = to as usize; }
        }
        candidates.push(Thought::ColorPermute(perm));
    }

    // Evaluate all candidates — the one with distance=0 across ALL pairs wins
    for candidate in &candidates {
        let mut _total_dist: u64 = 0;
        let mut all_match = true;
        for (inp, out) in train_pairs {
            let (dist, _) = thought_score(candidate, inp, out, rows, cols);
            _total_dist += dist;
            if dist > 0 { all_match = false; }
        }

        if all_match {
            // UNDERSTOOD — the residual-constructed thought works
            let sig = perception::transformation_signature(train_pairs);
            knowledge.remember(sig, candidate.clone(), rows, cols, ComprehensionRecord::empty());

            let predicted = candidate.apply_to_values(test_input, rows, cols);
            return Some((predicted, ThinkingResult {
                best_thought: candidate.clone(),
                distance: 0,
                understood: true,
                thoughts_evaluated: base_result.thoughts_evaluated + candidates.len() as u32,
                depth: 1,
            }));
        }
    }

    // Phase 5: Sluice conjoining — compose partial understandings
    // Collect all partial results (base vocabulary best + candidates)
    let mut partials = Vec::new();
    partials.push(PartialUnderstanding {
        thought: base_result.best_thought.clone(),
        distance: base_result.distance,
        entity_id: 0,
    });
    for candidate in &candidates {
        let total_dist: u64 = train_pairs.iter()
            .map(|(i, o)| thought_score(candidate, i, o, rows, cols).0)
            .sum();
        if total_dist < base_result.distance {
            partials.push(PartialUnderstanding {
                thought: candidate.clone(),
                distance: total_dist,
                entity_id: 0,
            });
        }
    }

    if let Some((compound, dist)) = conjoin_partial_understandings(&partials, train_pairs, rows, cols) {
        if dist == 0 {
            let sig = perception::transformation_signature(train_pairs);
            knowledge.remember(sig, compound.clone(), rows, cols, ComprehensionRecord::empty());
            let output = compound.apply_to_values(test_input, rows, cols);
            return Some((output, ThinkingResult {
                best_thought: compound,
                distance: 0,
                understood: true,
                thoughts_evaluated: base_result.thoughts_evaluated + candidates.len() as u32 + partials.len() as u32,
                depth: 2,
            }));
        }
    }

    // Return best effort
    result
}

// ═══════════════════════════════════════════════════════════════════════
// D.THINK.COGNITION.1 — The Internal Conversation
//
// think() is the top-level cognition function. It receives an observation
// and returns understanding — or the exact rational measurement of how
// far from understanding it reached.
//
// This is not an external operation. It IS thinking. The function:
// 1. Encodes the observation relationally (no semantic assignment)
// 2. Checks cognition — does the EpsilonTable recognize this orbit region?
// 3. Attempts value-level factoring across all training pairs
// 4. If factoring achieves jr=0: understanding. Return it.
// 5. If not: construct Delta, resolve via coordinator, measure C(Δ)
// 6. If C stuck: check transmutation need (m-expansion or n-expansion)
// 7. If transmutation needed: expand, lift, retry
// 8. Return: the full state — what was understood, what wasn't,
//    how far from understanding, which dimensions were exhausted
//
// The caller provides observations. The kernel thinks about them.
// How many thoughts that requires is the kernel's decision.
// ═══════════════════════════════════════════════════════════════════════

/// The result of thinking about an observation.
#[derive(Debug, Clone)]
pub struct ThoughtResult {
    /// Did the system achieve full understanding (jr=0)?
    pub understood: bool,
    /// Joint residual across all training pairs (0 = understood).
    /// Integer measurement from FactoredRule path (backward compat).
    pub joint_residual: u64,
    /// Holonomic joint residual — proportional measurement from algebraic path.
    /// |t/d - 1| per direction. Zero = exact proportional match.
    pub holonomic_residual: Q,
    /// The discovered rule (if any) — classification/measurement.
    pub rule: FactoredRule,
    /// Grid values derived by applying the algebraic operator to test input.
    /// None if no test input provided or algebraic path didn't converge.
    pub derived_output: Option<Vec<i64>>,
    /// The compound operator — the algebraic transmutation itself.
    /// None if understanding came from FactoredRule path.
    pub compound: Option<Operator>,
    /// Number of entities (n) in the observation.
    pub n: usize,
    /// Coordinate dimension (m) — may have expanded through transmutation.
    pub m: usize,
    /// Coherence of the relational Delta probe.
    pub coherence: Q,
    /// How the thought anchored to prior cognition.
    pub anchor: ThoughtAnchor,
    /// Whether transmutation was triggered during thinking.
    pub transmutation: Option<TransmutationEvent>,
    /// Number of resolution iterations the system performed.
    pub thoughts_formed: usize,
    /// BLAKE3 hash of the discovered rule (if understood).
    pub compound_hash: Option<[u8; 32]>,
}

/// A dimensional transmutation that occurred during thinking.
#[derive(Debug, Clone)]
pub struct TransmutationEvent {
    pub old_n: usize,
    pub old_m: usize,
    pub new_n: usize,
    pub new_m: usize,
    pub trigger: &'static str, // "m_expansion" or "n_expansion"
}

/// Think about an observation. The complete internal conversation.
///
/// `pairs`: training pairs as (source_values, target_values).
/// `m`: initial coordinate dimension.
/// `orbit_prefix`: first 4 bytes of rcf_identity for memory lookup (None = no prior cognition).
/// `max_iterations`: maximum resolution attempts before returning partial result.
/// `comprehension`: if provided, guides the algebraic disassembly path.
///   When comprehension says "relate", skip global value factoring and
///   derive inter-object. When "conjugate", derive per-object.
///   When None, fall back to blind value factoring (backward compatible).
///
/// Returns ThoughtResult — the full state of understanding achieved.
///
/// If `transmutation_predictor` is provided, the system checks whether
/// it has already internalized the transmutation law for this orbit region.
/// If yes: it predicts the expansion instead of re-deriving it from the residual.
/// This is evolution — the law is recalled, not computed.
pub fn thought(
    pairs: &[(Vec<i64>, Vec<i64>)],
    m: usize,
    orbit_prefix: Option<&[u8; 4]>,
    max_iterations: usize,
    transmutation_predictor: Option<&crate::sampler::EpsilonTable>,
) -> ThoughtResult {
    thought_with_comprehension(pairs, m, orbit_prefix, max_iterations, transmutation_predictor, None)
}

/// Think with comprehension — understanding informed by prior knowledge.
///
/// Comprehension tells the thought function HOW to think:
/// - "relate" → derive inter-object (template-at-displacement)
/// - "conjugate" → derive per-object (cluster-local rules)
/// - "auto" → blind value factoring (default)
///
/// The morphism (DimensionalBridge) is a first-class thought parameter.
/// When the bridge says Expansion(n=2), the thinking machinery knows:
/// one input cell generates a block of output cells. The comprehension
/// of scale is part of the thought, not metadata discarded before thinking.
///
/// The comprehension can come from:
/// 1. The sensory compound (computed this cycle)
/// 2. Recalled knowledge (recognized orbit, prior ComprehensionRecord)
/// 3. None (backward compatible — blind factoring)
pub fn thought_with_comprehension(
    pairs: &[(Vec<i64>, Vec<i64>)],
    m: usize,
    orbit_prefix: Option<&[u8; 4]>,
    max_iterations: usize,
    transmutation_predictor: Option<&crate::sampler::EpsilonTable>,
    comprehension: Option<&ComprehensionRecord>,
) -> ThoughtResult {
    if pairs.is_empty() {
        return ThoughtResult {
            understood: false, joint_residual: 0, holonomic_residual: Q::zero(),
            rule: FactoredRule::NoRule, derived_output: None, compound: None,
            n: 0, m, coherence: Q::zero(), anchor: ThoughtAnchor::Unanchored,
            transmutation: None, thoughts_formed: 0, compound_hash: None,
        };
    }

    let n = pairs[0].0.len();

    // ── Step 1: Determine anchor ──
    let anchor = match orbit_prefix {
        Some(_prefix) => ThoughtAnchor::MemoryAnchored { orbit_prefix: *_prefix },
        None => ThoughtAnchor::Unanchored,
    };

    // ── Step 2: Comprehension-guided first thought ──
    let semantic_intent = comprehension.map(|c| c.semantic_intent).unwrap_or("auto");

    // ── Step 2a: Dimensional comprehension — the morphism as first thought ──
    // When input and output have different sizes, the scale change IS the thought.
    // Don't pad. Don't pretend sizes are equal. Comprehend the dimensional relationship.
    let n_out = pairs[0].1.len();
    let dimensional = n != n_out;

    if dimensional {
        // Compute grid dimensions for input and output
        let mut gc_in = 1usize;
        let mut bc_in = 1usize;
        while gc_in * gc_in <= n { if n % gc_in == 0 { bc_in = gc_in; } gc_in += 1; }
        let cols_in = bc_in;
        let rows_in = n / cols_in.max(1);

        let mut gc_out = 1usize;
        let mut bc_out = 1usize;
        while gc_out * gc_out <= n_out { if n_out % gc_out == 0 { bc_out = gc_out; } gc_out += 1; }
        let cols_out = bc_out;
        let rows_out = n_out / cols_out.max(1);

        // Is the expansion an integer multiple? (e.g., 3x3 → 9x9)
        if rows_out >= rows_in && cols_out >= cols_in
            && rows_in > 0 && cols_in > 0
            && rows_out % rows_in == 0 && cols_out % cols_in == 0
        {
            let rf = rows_out / rows_in;
            let cf = cols_out / cols_in;

            // Self-similar expansion: output = input ⊗ input (Kronecker product)
            // Each input cell at (r,c) determines a rf×cf block in the output.
            // Non-zero cell → block is a copy of the input. Zero cell → block is all zeros.
            if rf == rows_in && cf == cols_in {
                // Exponent = 2: the input IS the operator on itself.
                // Test: for each training pair, does Kronecker product match?
                let mut kr_works = true;
                let mut kr_jr = 0u64;

                for (inp, out) in pairs {
                    let mut expected = vec![0i64; rows_out * cols_out];
                    for r in 0..rows_in {
                        for c in 0..cols_in {
                            let cell_val = inp[r * cols_in + c];
                            // This cell generates a block at (r*rf, c*cf) of size rf×cf
                            for br in 0..rf {
                                for bc in 0..cf {
                                    let out_r = r * rf + br;
                                    let out_c = c * cf + bc;
                                    let out_idx = out_r * cols_out + out_c;
                                    if out_idx < expected.len() {
                                        if cell_val != 0 {
                                            // Non-zero: copy the input pattern
                                            expected[out_idx] = inp[br * cols_in + bc];
                                        }
                                        // Zero: leave as 0
                                    }
                                }
                            }
                        }
                    }
                    // Measure residual
                    for k in 0..expected.len().min(out.len()) {
                        kr_jr += (expected[k] - out[k]).unsigned_abs();
                    }
                    if kr_jr > 0 { kr_works = false; }
                }

                if kr_works {
                    let hash = FactoredRule::NoRule.canonical_hash();
                    return ThoughtResult {
                        understood: true, joint_residual: 0, holonomic_residual: Q::zero(),
                        rule: FactoredRule::NoRule, derived_output: None, compound: None,
                        n, m, coherence: Q::zero(), anchor,
                        transmutation: Some(TransmutationEvent {
                            old_n: n, old_m: m, new_n: n_out, new_m: m,
                            trigger: "kronecker_expansion",
                        }),
                        thoughts_formed: 1,
                        compound_hash: Some(hash),
                    };
                }
            }

            // General integer expansion: output is rf×cf tiling of the input
            // Each input cell at (r,c) with value v generates a rf×cf block
            // Test: is the block content a function of the input cell value?
            let mut tile_works = true;
            for (inp, out) in pairs {
                for r in 0..rows_in {
                    for c in 0..cols_in {
                        let _cell_val = inp[r * cols_in + c];
                        // Check if this cell's block is consistent across all same-value cells
                        for br in 0..rf {
                            for bc in 0..cf {
                                let out_r = r * rf + br;
                                let out_c = c * cf + bc;
                                let out_idx = out_r * cols_out + out_c;
                                if out_idx >= out.len() { tile_works = false; break; }
                            }
                            if !tile_works { break; }
                        }
                        if !tile_works { break; }
                    }
                    if !tile_works { break; }
                }
                if !tile_works { break; }
            }
            // Even if tiling doesn't fully resolve, the bridge is computed.
            // Fall through to value factoring with dimensional awareness.
        }

        // For different-size pairs where expansion doesn't resolve:
        // Try value-level factoring on the overlapping portion.
        // This is partial comprehension — the system understands the value mapping
        // but not yet the dimensional relationship.
    }

    // Grid dimensions for Delta probe (step 3)
    let mut gc = 1usize;
    let mut best_cols_grid = 1usize;
    while gc * gc <= n { if n % gc == 0 { best_cols_grid = gc; } gc += 1; }
    let grid_cols = best_cols_grid;
    let grid_rows = n / grid_cols.max(1);

    // ── VIII.4: HashMap value-level derivation removed ──
    // Derivation flows through Delta resolution below.
    // The manifold resolves or reports honest H^1 residual. No proxy.
    let rule = FactoredRule::NoRule;
    let jr = 0u64;

    // ── Step 3: Construct Delta probe ──
    // Spectral dimension selected by metabolic horizon.
    // d = n(n-1)/2 × m. d_max = 1500. Richest affordable m.
    let probe_half_n = n * n.saturating_sub(1) / 2;
    let mut probe = [4usize, 1].iter()
        .find(|&&m| probe_half_n * m <= 1500)
        .map(|&m| match m {
            4 => perception::encode_grid_objects(&pairs[0].0, grid_rows, grid_cols),
            _ => {
                let entities: Vec<Vec<Q>> = pairs[0].0.iter()
                    .map(|&v| vec![Q::from(BigInt::from(v))])
                    .collect();
                perception::encode_relational(&entities)
            }
        })
        .unwrap_or_else(|| Delta::zero(1, 1));
    let mut current_m = probe.m;
    let mut current_n = probe.dim;
    let _coherence = coherence_functional(&probe);

    // ── Step 4: Coordinator resolution — iterated thoughts ──
    let mut thoughts_formed = if semantic_intent == "relate" || semantic_intent == "conjugate" { 2 } else { 1 };
    let mut transmutation: Option<TransmutationEvent> = None;

    for _iter in 0..max_iterations {
        let resolution = crate::coordinator::resolve(&probe);
        thoughts_formed += 1;

        // Check if resolution made progress
        if resolution.coherence_before.is_zero() {
            break; // Already coherent at Delta level
        }

        let eps_norm: Q = resolution.epsilon.iter()
            .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
            .sum();

        // ── Step 5: Transmutation — evolution first, computation second ──
        //
        // EVOLUTION: check if the system has internalized the transmutation law
        // for this orbit region. If yes: predict instead of compute.
        // This is the transition from navigating to BEING the landscape.
        if let (Some(prefix), Some(predictor)) = (orbit_prefix, transmutation_predictor) {
            if let Some(predicted_m) = predictor.predict_transmutation(prefix, current_m as u8) {
                let old_m = current_m;
                let new_m = predicted_m as usize;
                probe = crate::coordinator::expand_m(&probe, new_m);
                current_m = new_m;
                transmutation = Some(TransmutationEvent {
                    old_n: current_n, old_m, new_n: current_n, new_m,
                    trigger: "evolved_prediction",
                });
                thoughts_formed += 1;
                continue; // Retry at predicted dimension — no re-derivation needed
            }
        }

        // COMPUTATION: if no prediction available, derive transmutation from residual
        if !eps_norm.is_zero() {
            let ratio = if !resolution.predicted_coherence_after.is_zero() && !resolution.coherence_before.is_zero() {
                &resolution.predicted_coherence_after / &resolution.coherence_before
            } else {
                Q::zero()
            };
            let threshold = Q::new(BigInt::from(9), BigInt::from(10));
            if ratio > threshold {
                if let Some(new_m) = crate::coordinator::detect_m_expansion_need(&probe) {
                    let old_m = current_m;
                    probe = crate::coordinator::expand_m(&probe, new_m);
                    current_m = new_m;
                    transmutation = Some(TransmutationEvent {
                        old_n: current_n, old_m, new_n: current_n, new_m,
                        trigger: "m_expansion",
                    });
                    thoughts_formed += 1;
                    continue; // Retry at new dimension
                }
            }
        } else if !resolution.coherence_before.is_zero() {
            // Epsilon is zero but coherence is non-zero — n-expansion territory
            if let Some(new_n) = crate::coordinator::detect_dimensional_need(&probe) {
                let old_n = current_n;
                probe = crate::coordinator::expand_delta(&probe, new_n);
                current_n = new_n;
                transmutation = Some(TransmutationEvent {
                    old_n, old_m: current_m, new_n, new_m: current_m,
                    trigger: "n_expansion",
                });
                thoughts_formed += 1;
                continue;
            }
            break; // Can't expand further
        }

        // Apply resolution if it made progress
        if !eps_norm.is_zero() {
            let dirs = matrix::independent_dims(current_n);
            if let Some(op) = matrix::operator_from_epsilons(&resolution.epsilon, &dirs, current_n, 0) {
                if let Ok(applied) = op.apply(&probe) {
                    probe = crate::engine::pi_g_project(&applied);
                }
            }
        }
    }

    // ── Step 6: Re-evaluate after thinking ──
    // The value-level factoring may not have changed, but the Delta probe
    // tells us how far the relational structure is from coherence
    let final_coherence = coherence_functional(&probe);

    ThoughtResult {
        understood: false,
        joint_residual: jr,
        holonomic_residual: Q::zero(),
        rule,
        derived_output: None,
        compound: None,
        n: current_n,
        m: current_m,
        coherence: final_coherence,
        anchor,
        transmutation,
        thoughts_formed,
        compound_hash: None,
    }
}

