    // ─── STAGE 1 — Engine path verification ────────────────────────
    // Do the solved puzzles solve through the ENGINE (navigate on Delta)
    // or only through the LEGACY path (apply_to_values on flat arrays)?

    #[test]
    fn test_stage1_color_map_through_engine() {
        // 0d3d703e: color map 3→4, 1→5, 2→6
        // ALL THREE training pairs — joint residual is the real test
        let pairs = vec![
            (vec![3,1,2, 3,1,2, 3,1,2], vec![4,5,6, 4,5,6, 4,5,6]),
            (vec![2,3,8, 2,3,8, 2,3,8], vec![6,4,9, 6,4,9, 6,4,9]),
            (vec![5,8,6, 5,8,6, 5,8,6], vec![1,9,2, 1,9,2, 1,9,2]),
        ];

        // Derive value vector from pair 0
        let source_0 = perception::encode_grid_objects(&pairs[0].0, 3, 3);
        let target_0 = perception::encode_grid_objects(&pairs[0].1, 3, 3);
        let substrate = ThoughtSubstrate::new(&source_0);

        let value_result = substrate.navigate_value(
            &source_0, &target_0, &pairs[0].0, &pairs[0].1);

        if let Some((ref vc, ref vd_before, ref vd_after)) = value_result {
            eprintln!("0d3d703e pair0 G_VALUE: d_before={}, d_after={}", vd_before, vd_after);

            // Apply the SAME value vector to pairs 1 and 2
            // If it generalizes: the value vector IS the color map
            // If it doesn't: it was memorization of pair 0
            let mut all_correct = true;
            for (idx, (inp, out)) in pairs.iter().enumerate() {
                let predicted: Vec<i64> = inp.iter().zip(vc.iter())
                    .map(|(&v, change)| {
                        let n: i64 = change.numer().try_into().unwrap_or(0);
                        let d: i64 = change.denom().try_into().unwrap_or(1);
                        v + n / d
                    })
                    .collect();
                let matches = predicted == *out;
                eprintln!("  pair {}: predicted={:?} expected={:?} match={}",
                    idx, predicted, out, matches);
                if !matches { all_correct = false; }
            }

            if all_correct {
                eprintln!("  → Per-cell value vector generalizes (same grid structure)");
            } else {
                eprintln!("  → Per-cell value vector does NOT generalize");
            }
        }

        // VIII.4: factor_value_vectors tests removed — derivation flows through T.
    }

    #[test]
    fn test_evolve_understands_invert_as_cell_change() {
        // Color invert: 0→9, 1→8 — with single training example,
        // this IS understood as CellChange [+9,+7,+5,+3].
        // That's correct: from ONE example, per-cell change is exact.
        // With MULTIPLE examples showing the PATTERN (invert), the evolve
        // path would discover ColorPermute. But single-example CellChange
        // is valid understanding.
        let mut kb = KnowledgeBase::new();
        let pairs = vec![
            (vec![0, 1, 2, 3], vec![9, 8, 7, 6]),
        ];
        let test = vec![0, 1, 2, 3];
        let result = evolve_and_solve(&pairs, &test, 1, 4, &mut kb);
        assert!(result.is_some());
        let (pred, res) = result.unwrap();
        assert!(res.understood, "Must understand as CellChange");
        // CellChange [+9,+7,+5,+3] applied to [0,1,2,3] = [9,8,7,6]
        assert_eq!(pred, vec![9, 8, 7, 6]);
    }

    // ─── T.TRANSMUTE — Transmutation Tests ───────────────────────────

    #[test]
    fn test_substrate_transmute_n_preserves_congruence() {
        use crate::engine::Delta;
        use crate::matrix;

        // Build a 3×3 substrate with a compound operator
        let mut d3 = Delta::zero(3, 1);
        d3.set_antisym(0, 1, vec![Q::new(BigInt::from(1), BigInt::from(1))]);
        d3.set_antisym(1, 2, vec![Q::new(BigInt::from(1), BigInt::from(2))]);
        d3.set_antisym(0, 2, vec![Q::new(BigInt::from(1), BigInt::from(3))]);

        let mut substrate = ThoughtSubstrate::new(&d3);
        assert_eq!(substrate.n, 3);

        // Accept a thought at n=3
        let dirs = matrix::independent_dims(3);
        let eps = vec![
            Q::new(BigInt::from(1), BigInt::from(100)),
            Q::new(BigInt::from(-1), BigInt::from(200)),
            Q::new(BigInt::from(1), BigInt::from(300)),
        ];
        if let Some(op) = matrix::operator_from_epsilons(&eps, &dirs, 3, 1) {
            let _ = substrate.accept_thought(&op, &d3);
        }
        let compound_before = substrate.compound.matrix.clone();

        // Expand delta to 4×4
        let d4 = crate::coordinator::expand_delta(&d3, 4);
        assert_eq!(d4.dim, 4);

        // Transmute the substrate
        assert!(substrate.transmute_n(&d4), "transmutation must succeed");
        assert_eq!(substrate.n, 4);

        // Verify: top-left 3×3 block of compound is preserved
        for i in 0..3 {
            for j in 0..3 {
                assert_eq!(substrate.compound.matrix[i][j], compound_before[i][j],
                    "compound must be preserved at ({},{})", i, j);
            }
        }

        // Verify: new dimension is identity
        assert_eq!(substrate.compound.matrix[3][3], Q::one());
        for i in 0..3 {
            assert!(substrate.compound.matrix[3][i].is_zero());
            assert!(substrate.compound.matrix[i][3].is_zero());
        }
    }

    #[test]
    fn test_substrate_transmute_rejects_smaller() {
        let d = Delta::zero(3, 1);
        let mut substrate = ThoughtSubstrate::new(&d);
        let d2 = Delta::zero(2, 1);
        assert!(!substrate.transmute_n(&d2), "cannot transmute to smaller dimension");
    }

    #[test]
    fn test_m_expansion_preserves_antisymmetry() {
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![Q::new(BigInt::from(1), BigInt::from(1))]);
        d.set_antisym(1, 2, vec![Q::new(BigInt::from(1), BigInt::from(2))]);
        d.set_antisym(0, 2, vec![Q::new(BigInt::from(1), BigInt::from(3))]);

        let expanded = crate::coordinator::expand_m(&d, 2);

        // Verify antisymmetry in ALL coordinates including new
        for i in 0..3 {
            for j in 0..3 {
                for l in 0..2 {
                    let sum = &expanded.entries[i][j][l] + &expanded.entries[j][i][l];
                    assert!(sum.is_zero(),
                        "antisymmetry violated at ({},{},{}) after m-expansion", i, j, l);
                }
            }
        }
    }
